import React, { useState } from 'react';
import type { Reminder, ReminderType } from '../types/schema';

interface ReminderManagementProps {
  reminders: Reminder[];
  onUpdate: (id: string, updates: Partial<Reminder>) => Promise<void>;
  onDelete: (id: string) => Promise<void>;
  onCreate: (reminder: Omit<Reminder, 'id' | 'created_at' | 'updated_at' | 'next_send_at'>) => Promise<void>;
  loading?: boolean;
}

const ReminderManagement: React.FC<ReminderManagementProps> = ({
  reminders,
  onUpdate,
  onDelete,
  onCreate,
  loading = false,
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Omit<Reminder, 'id' | 'created_at' | 'updated_at' | 'next_send_at'>>({
    child_id: '',
    parent_id: '',
    type: 'custom',
    title: '',
    message: '',
    schedule_time: '07:00',
    is_enabled: true,
    frequency: 'daily',
    days_of_week: [1, 2, 3, 4, 5],
  });

  const reminderTypeIcons: Record<ReminderType, string> = {
    morning_greeting: '🌅',
    task_reminder: '⏰',
    exam_countdown: '📚',
    missed_task_alert: '⚠️',
    achievement: '🏆',
    custom: '📢',
  };

  const reminderTypeLabels: Record<ReminderType, string> = {
    morning_greeting: 'Morning Greeting',
    task_reminder: 'Task Reminder',
    exam_countdown: 'Exam Countdown',
    missed_task_alert: 'Missed Task Alert',
    achievement: 'Achievement Notification',
    custom: 'Custom Reminder',
  };

  const handleAddReminder = async () => {
    try {
      await onCreate(formData);
      setShowAddForm(false);
      resetForm();
    } catch (err) {
      console.error('Failed to create reminder:', err);
    }
  };

  const handleUpdateReminder = async (id: string) => {
    const reminder = reminders.find(r => r.id === id);
    if (!reminder) return;

    try {
      const updates = {
        title: formData.title,
        message: formData.message,
        schedule_time: formData.schedule_time,
        is_enabled: formData.is_enabled,
        frequency: formData.frequency,
        days_of_week: formData.days_of_week,
      };
      await onUpdate(id, updates);
      setEditingId(null);
      resetForm();
    } catch (err) {
      console.error('Failed to update reminder:', err);
    }
  };

  const handleEditClick = (reminder: Reminder) => {
    setFormData({
      child_id: reminder.child_id,
      parent_id: reminder.parent_id,
      type: reminder.type,
      title: reminder.title,
      message: reminder.message,
      schedule_time: reminder.schedule_time,
      is_enabled: reminder.is_enabled,
      frequency: reminder.frequency,
      days_of_week: reminder.days_of_week,
      task_id: reminder.task_id,
      exam_event_id: reminder.exam_event_id,
    });
    setEditingId(reminder.id);
  };

  const resetForm = () => {
    setFormData({
      child_id: '',
      parent_id: '',
      type: 'custom',
      title: '',
      message: '',
      schedule_time: '07:00',
      is_enabled: true,
      frequency: 'daily',
      days_of_week: [1, 2, 3, 4, 5],
    });
  };

  const toggleDayOfWeek = (day: number) => {
    const days = formData.days_of_week || [];
    if (days.includes(day)) {
      setFormData({ ...formData, days_of_week: days.filter(d => d !== day) });
    } else {
      setFormData({ ...formData, days_of_week: [...days, day].sort() });
    }
  };

  const dayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-md p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white">🔔 Reminders</h2>
        <button
          onClick={() => setShowAddForm(!showAddForm)}
          className="px-4 py-2 bg-blue-500 hover:bg-blue-600 text-white rounded-lg transition"
        >
          {showAddForm ? 'Cancel' : '+ Add Reminder'}
        </button>
      </div>

      {/* Add/Edit Form */}
      {(showAddForm || editingId) && (
        <div className="mb-6 p-4 bg-gray-100 dark:bg-gray-700 rounded-lg">
          <h3 className="text-lg font-semibold mb-4 text-gray-900 dark:text-white">
            {editingId ? 'Edit Reminder' : 'Create New Reminder'}
          </h3>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Type
              </label>
              <select
                value={formData.type}
                onChange={(e) => setFormData({ ...formData, type: e.target.value as ReminderType })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
              >
                {Object.entries(reminderTypeLabels).map(([key, label]) => (
                  <option key={key} value={key}>
                    {reminderTypeIcons[key as ReminderType]} {label}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Title
              </label>
              <input
                type="text"
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                placeholder="Reminder title"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Message
              </label>
              <textarea
                value={formData.message}
                onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                placeholder="Reminder message"
                rows={3}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Frequency
                </label>
                <select
                  value={formData.frequency}
                  onChange={(e) => setFormData({ ...formData, frequency: e.target.value as any })}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                >
                  <option value="once">Once</option>
                  <option value="daily">Daily</option>
                  <option value="weekly">Weekly</option>
                </select>
              </div>

              {(formData.frequency === 'daily' || formData.frequency === 'weekly') && (
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                    Time
                  </label>
                  <input
                    type="time"
                    value={formData.schedule_time}
                    onChange={(e) => setFormData({ ...formData, schedule_time: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                  />
                </div>
              )}
            </div>

            {formData.frequency === 'weekly' && (
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Days of Week
                </label>
                <div className="flex gap-2 flex-wrap">
                  {dayLabels.map((label, day) => (
                    <button
                      key={day}
                      onClick={() => toggleDayOfWeek(day)}
                      className={`px-3 py-2 rounded transition ${
                        (formData.days_of_week || []).includes(day)
                          ? 'bg-blue-500 text-white'
                          : 'bg-gray-300 dark:bg-gray-600 text-gray-700 dark:text-gray-300'
                      }`}
                    >
                      {label}
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="flex items-center">
              <input
                type="checkbox"
                id="enabled"
                checked={formData.is_enabled}
                onChange={(e) => setFormData({ ...formData, is_enabled: e.target.checked })}
                className="mr-2"
              />
              <label htmlFor="enabled" className="text-sm font-medium text-gray-700 dark:text-gray-300">
                Enabled
              </label>
            </div>
          </div>

          <div className="flex gap-3 mt-4">
            <button
              onClick={() => (editingId ? handleUpdateReminder(editingId) : handleAddReminder())}
              disabled={loading}
              className="flex-1 px-4 py-2 bg-green-500 hover:bg-green-600 text-white rounded-lg transition disabled:opacity-50"
            >
              {loading ? 'Saving...' : editingId ? 'Update' : 'Create'}
            </button>
            <button
              onClick={() => {
                setEditingId(null);
                setShowAddForm(false);
                resetForm();
              }}
              className="flex-1 px-4 py-2 bg-gray-400 hover:bg-gray-500 text-white rounded-lg transition"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Reminders List */}
      <div className="space-y-3">
        {reminders.length === 0 ? (
          <p className="text-gray-500 dark:text-gray-400 text-center py-8">
            No reminders configured yet. Create one to get started!
          </p>
        ) : (
          reminders.map(reminder => (
            <div
              key={reminder.id}
              className={`p-4 rounded-lg border-l-4 transition ${
                reminder.is_enabled
                  ? 'bg-white dark:bg-gray-700 border-blue-500'
                  : 'bg-gray-100 dark:bg-gray-700 border-gray-400 opacity-75'
              }`}
            >
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <span className="text-2xl">
                      {reminderTypeIcons[reminder.type]}
                    </span>
                    <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                      {reminder.title}
                    </h3>
                    <span className="text-xs px-2 py-1 bg-blue-100 dark:bg-blue-900 text-blue-800 dark:text-blue-200 rounded">
                      {reminderTypeLabels[reminder.type]}
                    </span>
                  </div>
                  <p className="text-sm text-gray-600 dark:text-gray-400 mb-2">{reminder.message}</p>
                  <div className="flex gap-4 text-xs text-gray-500 dark:text-gray-400">
                    <span>⏰ {reminder.schedule_time || 'No specific time'}</span>
                    <span>📅 {reminder.frequency}</span>
                    {reminder.frequency === 'weekly' && reminder.days_of_week && (
                      <span>
                        📆{' '}
                        {reminder.days_of_week
                          .map(d => dayLabels[d])
                          .join(', ')}
                      </span>
                    )}
                    <span className={reminder.is_enabled ? 'text-green-600' : 'text-red-600'}>
                      {reminder.is_enabled ? '✓ Active' : '✗ Disabled'}
                    </span>
                  </div>
                </div>

                <div className="flex gap-2 ml-4">
                  <button
                    onClick={() => handleEditClick(reminder)}
                    className="px-3 py-1 bg-yellow-500 hover:bg-yellow-600 text-white rounded transition text-sm"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => {
                      if (confirm('Delete this reminder?')) {
                        onDelete(reminder.id);
                      }
                    }}
                    className="px-3 py-1 bg-red-500 hover:bg-red-600 text-white rounded transition text-sm"
                  >
                    Delete
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default ReminderManagement;

import React, { useState } from 'react';
import type { RewardItem } from '../types/schema';

interface RewardManagementProps {
  rewards: RewardItem[];
  onCreateReward: (reward: Omit<RewardItem, 'id' | 'created_at' | 'updated_at'>) => Promise<void>;
  onUpdateReward: (id: string, updates: Partial<RewardItem>) => Promise<void>;
  onDeleteReward: (id: string) => Promise<void>;
  loading?: boolean;
}

const RewardManagement: React.FC<RewardManagementProps> = ({
  rewards,
  onCreateReward,
  onUpdateReward,
  onDeleteReward,
  loading = false,
}) => {
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Omit<RewardItem, 'id' | 'created_at' | 'updated_at'>>({
    parent_id: '',
    name: '',
    description: '',
    star_cost: 20,
    icon: '🎁',
    category: 'item',
    is_available: true,
  });

  const categoryOptions = [
    { value: 'screen_time', label: '📱 Screen Time', icon: '📱' },
    { value: 'treat', label: '🍦 Treat', icon: '🍦' },
    { value: 'item', label: '🎁 Item', icon: '🎁' },
    { value: 'experience', label: '✨ Experience', icon: '✨' },
    { value: 'privilege', label: '👑 Privilege', icon: '👑' },
    { value: 'learning', label: '📚 Learning', icon: '📚' },
    { value: 'activity', label: '🎯 Activity', icon: '🎯' },
  ];

  const emojiOptions = ['🎮', '📱', '📺', '🎬', '🍦', '🍕', '🍰', '🧸', '🎁', '🚗', '📵', '💰', '👫', '🏆', '📚', '⚽', '🎨'];

  const handleAddReward = async () => {
    if (!formData.name || !formData.description) {
      alert('Please fill in all fields');
      return;
    }

    try {
      await onCreateReward(formData);
      setShowAddForm(false);
      resetForm();
    } catch (err) {
      console.error('Failed to create reward:', err);
      alert('Failed to create reward');
    }
  };

  const handleUpdateReward = async (id: string) => {
    try {
      await onUpdateReward(id, formData as any);
      setEditingId(null);
      resetForm();
    } catch (err) {
      console.error('Failed to update reward:', err);
      alert('Failed to update reward');
    }
  };

  const handleEditClick = (reward: RewardItem) => {
    setFormData({
      parent_id: reward.parent_id,
      name: reward.name,
      description: reward.description,
      star_cost: reward.star_cost,
      icon: reward.icon,
      category: reward.category,
      is_available: reward.is_available,
      max_redemptions_per_week: reward.max_redemptions_per_week,
    });
    setEditingId(reward.id);
  };

  const resetForm = () => {
    setFormData({
      parent_id: '',
      name: '',
      description: '',
      star_cost: 20,
      icon: '🎁',
      category: 'item',
      is_available: true,
    });
  };

  return (
    <div className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm dark:border-white/10 dark:bg-white/[0.04]">
      <div className="mb-5 flex flex-wrap items-start justify-between gap-3">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white">🎁 Catalogue Items</h2>
          <p className="mt-1 text-sm text-gray-500 dark:text-white/55">Each item has an emoji, category, and star cost visible to the child.</p>
        </div>
        <button
          onClick={() => setShowAddForm(!showAddForm)}
          className="rounded-xl bg-blue-500 px-4 py-2 text-sm font-bold text-white transition hover:bg-blue-600"
        >
          {showAddForm ? 'Cancel' : '+ Add Reward'}
        </button>
      </div>

      {/* Add/Edit Form */}
      {(showAddForm || editingId) && (
        <div className="mb-6 rounded-2xl border border-slate-200 bg-gray-100 p-4 dark:border-white/10 dark:bg-black/20">
          <h3 className="text-lg font-semibold mb-4 text-gray-900 dark:text-white">
            {editingId ? 'Edit Reward' : 'Create New Reward'}
          </h3>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Reward Name
              </label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                placeholder="e.g., Extra Gaming Time"
              />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Description
              </label>
              <textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                placeholder="Describe what this reward includes"
                rows={2}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Reward Cost (Stars)
                </label>
                <input
                  type="number"
                  value={formData.star_cost}
                  onChange={(e) => setFormData({ ...formData, star_cost: parseInt(e.target.value) })}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                  min="1"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                  Category
                </label>
                <select
                  value={formData.category}
                  onChange={(e) => setFormData({ ...formData, category: e.target.value as any })}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                >
                  {categoryOptions.map(cat => (
                    <option key={cat.value} value={cat.value}>
                      {cat.icon} {cat.label}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                Emoji Icon
              </label>
              <div className="flex gap-2 flex-wrap">
                {emojiOptions.map(emoji => (
                  <button
                    key={emoji}
                    onClick={() => setFormData({ ...formData, icon: emoji })}
                    className={`text-2xl p-2 rounded transition ${
                      formData.icon === emoji
                        ? 'bg-blue-500 ring-2 ring-blue-600'
                        : 'bg-gray-300 dark:bg-gray-600 hover:bg-gray-400'
                    }`}
                  >
                    {emoji}
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
                Max Redemptions Per Week (optional)
              </label>
              <input
                type="number"
                value={formData.max_redemptions_per_week || ''}
                onChange={(e) => setFormData({ ...formData, max_redemptions_per_week: e.target.value ? parseInt(e.target.value) : undefined })}
                className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg dark:bg-gray-600 dark:text-white"
                placeholder="Leave empty for unlimited"
                min="1"
              />
            </div>

            <div className="flex items-center">
              <input
                type="checkbox"
                id="available"
                checked={formData.is_available}
                onChange={(e) => setFormData({ ...formData, is_available: e.target.checked })}
                className="mr-2"
              />
              <label htmlFor="available" className="text-sm font-medium text-gray-700 dark:text-gray-300">
                Available for redemption
              </label>
            </div>
          </div>

          <div className="mt-4 flex gap-3">
            <button
              onClick={() => (editingId ? handleUpdateReward(editingId) : handleAddReward())}
              disabled={loading}
              className="flex-1 rounded-xl bg-green-500 px-4 py-2 font-bold text-white transition hover:bg-green-600 disabled:opacity-50"
            >
              {loading ? 'Saving...' : editingId ? 'Update' : 'Create'}
            </button>
            <button
              onClick={() => {
                setEditingId(null);
                setShowAddForm(false);
                resetForm();
              }}
              className="flex-1 rounded-xl bg-gray-400 px-4 py-2 font-bold text-white transition hover:bg-gray-500"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Rewards List */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {rewards.length === 0 ? (
          <div className="col-span-full rounded-2xl border border-dashed border-slate-300 py-10 text-center dark:border-white/10">
            <p className="text-gray-500 dark:text-gray-400">
              No catalogue items yet. Add a reward or seed the starter catalogue.
            </p>
          </div>
        ) : (
          rewards.map(reward => (
            <div
              key={reward.id}
              className={`rounded-2xl border p-4 transition ${
                reward.is_available
                  ? 'border-blue-200 bg-blue-50 dark:border-blue-500/30 dark:bg-blue-500/10'
                  : 'border-gray-300 bg-gray-50 opacity-75 dark:border-white/10 dark:bg-white/5'
              }`}
            >
              <div className="flex items-start justify-between mb-2">
                <div className="text-4xl">{reward.icon}</div>
                <div className="flex gap-2">
                  <button
                    onClick={() => handleEditClick(reward)}
                    className="px-2 py-1 bg-yellow-500 hover:bg-yellow-600 text-white rounded transition text-sm"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => {
                      if (confirm('Delete this reward?')) {
                        onDeleteReward(reward.id);
                      }
                    }}
                    className="px-2 py-1 bg-red-500 hover:bg-red-600 text-white rounded transition text-sm"
                  >
                    Delete
                  </button>
                </div>
              </div>

              <h3 className="font-bold text-lg text-gray-900 dark:text-white mb-1">
                {reward.name}
              </h3>
              <p className="text-sm text-gray-600 dark:text-gray-400 mb-3">
                {reward.description}
              </p>

              <div className="space-y-1">
                <p className="text-sm">
                  <span className="font-semibold">⭐ Cost:</span> {reward.star_cost} stars
                </p>
                <p className="text-sm">
                  <span className="font-semibold">📂 Category:</span> {reward.category}
                </p>
                {reward.max_redemptions_per_week && (
                  <p className="text-sm">
                    <span className="font-semibold">📊 Max/Week:</span> {reward.max_redemptions_per_week}
                  </p>
                )}
                <p className="text-sm">
                  <span className="font-semibold">Status:</span>{' '}
                  {reward.is_available ? '✅ Available' : '❌ Unavailable'}
                </p>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default RewardManagement;

import React, { useState } from 'react';
import clsx from 'clsx';
import { useRoutines } from '../../hooks/useRoutines';
import { useToast } from '../../contexts/ToastContext';
import type { ChildProfile, Routine } from '../../types/schema';
import { Clock, Plus, Trash2, Edit2, Calendar, CheckSquare } from 'lucide-react';

interface RoutineManagementProps {
  familyId: string;
  childrenProfiles: ChildProfile[];
}

const DAY_RANGE_LABELS = {
  weekday: '📅 Weekdays (Mon–Fri)',
  weekend: '🏖️ Weekend (Sat–Sun)',
  everyday: '📆 Every Day',
} as const;

const DAY_RANGE_COLORS = {
  weekday: 'bg-blue-100 text-blue-700 dark:bg-blue-500/20 dark:text-blue-300',
  weekend: 'bg-purple-100 text-purple-700 dark:bg-purple-500/20 dark:text-purple-300',
  everyday: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-500/20 dark:text-emerald-300',
};

const EMPTY_FORM = {
  title: '',
  startTime: '07:00',
  endTime: '08:00',
  points: '' as number | '',
  icon: '📝',
  childId: '',
  dayRange: 'everyday' as Routine['day_range'],
  requiresApproval: false,
};

export function RoutineManagement({ familyId, childrenProfiles }: RoutineManagementProps) {
  const { routines, createRoutine, updateRoutine, archiveRoutine, loading } = useRoutines(familyId);
  const { addToast } = useToast();

  const [showModal, setShowModal] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState({ ...EMPTY_FORM });

  const activeRoutines = routines.filter(r => r.status === 'active');
  const weekdayRoutines = activeRoutines.filter(r => r.day_range === 'weekday' || r.day_range === 'everyday');
  const weekendRoutines = activeRoutines.filter(r => r.day_range === 'weekend' || r.day_range === 'everyday');

  const openCreate = () => {
    setEditId(null);
    setForm({ ...EMPTY_FORM });
    setShowModal(true);
  };

  const openEdit = (r: Routine) => {
    setEditId(r.id);
    setForm({
      title: r.title,
      startTime: r.start_time || r.schedule_time || '07:00',
      endTime: r.end_time || '08:00',
      points: r.points,
      icon: r.icon || '📝',
      childId: r.child_id || '',
      dayRange: r.day_range || 'everyday',
      requiresApproval: r.requires_approval ?? false,
    });
    setShowModal(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.title || !form.startTime || !form.endTime || form.points === '') {
      addToast('Please fill all required fields.', 'error');
      return;
    }
    if (form.endTime <= form.startTime) {
      addToast('End time must be after start time.', 'error');
      return;
    }

    try {
      const payload: Omit<Routine, 'id' | 'created_at' | 'updated_at' | 'streak'> = {
        family_id: familyId,
        child_id: form.childId || null,
        title: form.title.trim(),
        start_time: form.startTime,
        end_time: form.endTime,
        day_range: form.dayRange,
        points: Number(form.points),
        icon: form.icon || '📝',
        requires_approval: form.requiresApproval,
        created_by: 'parent',
        status: 'active',
      };

      if (editId) {
        await updateRoutine(editId, payload);
        addToast('Routine updated!', 'success');
      } else {
        await createRoutine(payload);
        addToast('Routine created!', 'success');
      }
      setShowModal(false);
    } catch (error) {
      addToast('Failed to save routine. Check Firestore rules.', 'error');
    }
  };

  const handleArchive = async (id: string) => {
    if (!confirm('Archive this routine?')) return;
    try {
      await archiveRoutine(id);
      addToast('Routine archived.', 'success');
    } catch {
      addToast('Failed to archive.', 'error');
    }
  };

  const RoutineCard = ({ routine }: { routine: Routine }) => (
    <div className="rounded-2xl border p-4 bg-white dark:bg-white/5 border-slate-200 dark:border-white/10 flex flex-col justify-between hover:shadow-lg transition-shadow">
      <div>
        <div className="flex items-start justify-between mb-3">
          <div className="text-3xl bg-slate-100 dark:bg-white/10 p-2 rounded-xl">{routine.icon || '📝'}</div>
          <div className="flex flex-col items-end gap-1">
            <span className={clsx('text-xs font-bold px-2 py-0.5 rounded-full', DAY_RANGE_COLORS[routine.day_range || 'everyday'])}>
              {routine.day_range === 'weekday' ? 'Weekdays' : routine.day_range === 'weekend' ? 'Weekend' : 'Every Day'}
            </span>
            <span className="text-xs font-bold bg-cyan-100 text-cyan-700 dark:bg-cyan-500/20 dark:text-cyan-300 px-2 py-0.5 rounded-full flex items-center gap-1">
              <Clock size={11} /> {routine.start_time || routine.schedule_time} – {routine.end_time || '—'}
            </span>
          </div>
        </div>
        <h3 className="font-bold text-base text-slate-900 dark:text-white">{routine.title}</h3>
        <div className="flex items-center gap-3 mt-2">
          <p className="text-sm font-semibold text-emerald-600 dark:text-emerald-400">⭐ {routine.points} stars</p>
          {routine.requires_approval && (
            <span className="text-xs font-bold text-amber-600 dark:text-amber-400 flex items-center gap-1">
              <CheckSquare size={11} /> Needs approval
            </span>
          )}
        </div>
        <p className="text-xs text-slate-500 dark:text-white/50 mt-1">
          {routine.child_id
            ? childrenProfiles.find(c => c.id === routine.child_id)?.name || 'Unknown'
            : 'All Children'}
        </p>
      </div>
      <div className="flex gap-2 mt-4 pt-3 border-t border-slate-100 dark:border-white/5">
        <button
          onClick={() => openEdit(routine)}
          className="flex-1 py-1.5 rounded-lg text-xs font-bold bg-slate-100 text-slate-600 hover:bg-slate-200 dark:bg-white/10 dark:text-white/80 dark:hover:bg-white/20 transition-colors flex items-center justify-center gap-1"
        >
          <Edit2 size={13} /> Edit
        </button>
        <button
          onClick={() => handleArchive(routine.id)}
          className="flex-1 py-1.5 rounded-lg text-xs font-bold bg-rose-50 text-rose-600 hover:bg-rose-100 dark:bg-rose-500/10 dark:text-rose-400 dark:hover:bg-rose-500/20 transition-colors flex items-center justify-center gap-1"
        >
          <Trash2 size={13} /> Archive
        </button>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h2 className="text-xl font-bold flex items-center gap-2">
            <Clock className="text-cyan-500" /> Routines
          </h2>
          <p className="text-sm text-slate-500 dark:text-white/60">
            Create weekday and weekend habits for your children.
          </p>
        </div>
        <button
          onClick={openCreate}
          className="flex items-center gap-2 rounded-xl bg-cyan-500 px-4 py-2 text-sm font-bold text-white hover:bg-cyan-600 transition-colors shadow-lg shadow-cyan-500/20"
        >
          <Plus size={16} /> Add Routine
        </button>
      </div>

      {loading ? (
        <p className="text-sm text-slate-500 animate-pulse">Loading routines...</p>
      ) : activeRoutines.length === 0 ? (
        <div className="rounded-2xl border border-dashed border-slate-300 dark:border-white/10 p-10 text-center">
          <p className="text-slate-400 dark:text-white/40 text-sm">No routines yet — create your first daily habit!</p>
        </div>
      ) : (
        <div className="space-y-8">
          {/* Weekday routines */}
          {weekdayRoutines.length > 0 && (
            <div>
              <div className="flex items-center gap-2 mb-4">
                <Calendar size={16} className="text-blue-500" />
                <h3 className="text-sm font-black uppercase tracking-wider text-blue-600 dark:text-blue-400">
                  Weekday Routines (Mon–Fri)
                </h3>
                <span className="ml-auto text-xs font-bold bg-blue-100 text-blue-600 dark:bg-blue-500/20 dark:text-blue-300 px-2 py-0.5 rounded-full">
                  {weekdayRoutines.length}
                </span>
              </div>
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {weekdayRoutines.map(r => <RoutineCard key={r.id} routine={r} />)}
              </div>
            </div>
          )}

          {/* Weekend routines */}
          {weekendRoutines.length > 0 && (
            <div>
              <div className="flex items-center gap-2 mb-4">
                <Calendar size={16} className="text-purple-500" />
                <h3 className="text-sm font-black uppercase tracking-wider text-purple-600 dark:text-purple-400">
                  Weekend Routines (Sat–Sun)
                </h3>
                <span className="ml-auto text-xs font-bold bg-purple-100 text-purple-600 dark:bg-purple-500/20 dark:text-purple-300 px-2 py-0.5 rounded-full">
                  {weekendRoutines.length}
                </span>
              </div>
              <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                {weekendRoutines.map(r => <RoutineCard key={r.id} routine={r} />)}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
          <div className="w-full max-w-lg rounded-2xl bg-white dark:bg-[#1a1f3c] shadow-2xl border border-slate-200 dark:border-white/10 overflow-hidden">
            <div className="px-6 py-4 border-b border-slate-100 dark:border-white/10 flex items-center justify-between">
              <h3 className="text-lg font-bold text-slate-900 dark:text-white">
                {editId ? 'Edit Routine' : 'Create Routine'}
              </h3>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-700 dark:hover:text-white transition-colors">✕</button>
            </div>

            <form onSubmit={handleSave} className="p-6 space-y-4 overflow-y-auto max-h-[80vh]">
              {/* Title */}
              <div>
