                  />
                </div>
                <div>
                  <label className="block text-xs font-bold uppercase tracking-wider mb-1 text-slate-500 dark:text-white/60">Icon (Emoji)</label>
                  <input
                    value={form.icon}
                    onChange={e => setForm(f => ({ ...f, icon: e.target.value }))}
                    className="w-full rounded-xl border border-slate-300 dark:border-white/10 bg-white dark:bg-black/20 px-4 py-2.5 text-sm text-slate-900 dark:text-white focus:ring-2 focus:ring-cyan-500/50 outline-none"
                  />
                </div>
              </div>

              {/* Assign to Child */}
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider mb-1 text-slate-500 dark:text-white/60">Assign To</label>
                <select
                  value={form.childId}
                  onChange={e => setForm(f => ({ ...f, childId: e.target.value }))}
                  className="w-full rounded-xl border border-slate-300 dark:border-white/10 bg-white dark:bg-black/20 px-4 py-2.5 text-sm text-slate-900 dark:text-white focus:ring-2 focus:ring-cyan-500/50 outline-none"
                >
                  <option value="">All Children</option>
                  {childrenProfiles.map(c => (
                    <option key={c.id} value={c.id}>{c.name}</option>
                  ))}
                </select>
              </div>

              {/* Requires Approval */}
              <label className="flex items-center gap-3 cursor-pointer p-3 rounded-xl border border-slate-200 dark:border-white/10 hover:bg-slate-50 dark:hover:bg-white/5 transition-colors">
                <input
                  type="checkbox"
                  checked={form.requiresApproval}
                  onChange={e => setForm(f => ({ ...f, requiresApproval: e.target.checked }))}
                  className="w-4 h-4 rounded accent-cyan-500"
                />
                <div>
                  <p className="text-sm font-bold text-slate-800 dark:text-white">Requires Parent Approval</p>
                  <p className="text-xs text-slate-500 dark:text-white/50">Stars are awarded after you approve the completion.</p>
                </div>
              </label>

              <div className="mt-2 pt-4 border-t border-slate-100 dark:border-white/10 flex justify-end gap-3">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="px-4 py-2 rounded-xl text-sm font-bold border border-slate-200 dark:border-white/10 text-slate-600 dark:text-white/70 hover:bg-slate-50 dark:hover:bg-white/5"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-2 rounded-xl text-sm font-bold bg-cyan-500 text-white hover:bg-cyan-400 transition-colors shadow-lg shadow-cyan-500/30"
                >
                  {editId ? 'Save Changes' : 'Create Routine'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

// Import the functions you need from the SDKs you need
import { initializeApp } from "firebase/app";
import { getAnalytics } from "firebase/analytics";
import type { Analytics } from "firebase/analytics";
import { connectFirestoreEmulator, getFirestore } from "firebase/firestore";
import type { Firestore } from "firebase/firestore";
import { connectAuthEmulator, getAuth } from "firebase/auth";
import type { Auth } from "firebase/auth";
import { connectStorageEmulator, getStorage } from "firebase/storage";
import type { FirebaseStorage } from "firebase/storage";
import { getMessaging } from "firebase/messaging";
import type { Messaging } from "firebase/messaging";
import {
  getFirebaseClientConfig,
  resolveFirebaseRuntimeEnv,
  type FirebaseClientConfig,
  type FirebaseRuntimeEnv
} from "./firebaseEnvironment";

const runtimeHostname =
  typeof globalThis !== 'undefined' && 'location' in globalThis
    ? globalThis.location.hostname.toLowerCase()
    : '';
const emulatorHost = runtimeHostname || '127.0.0.1';

const isLocalRuntime =
  Boolean(import.meta.env.DEV) ||
  runtimeHostname === 'localhost' ||
  runtimeHostname === '127.0.0.1' ||
  runtimeHostname === '::1' ||
  runtimeHostname.endsWith('.local');

const allowProdOnLocal =
  String(import.meta.env.VITE_ALLOW_PROD_ON_LOCAL ?? '').toLowerCase() === 'true';

const requestedEnv = resolveFirebaseRuntimeEnv(import.meta.env.VITE_APP_ENV);
export const activeFirebaseEnv: FirebaseRuntimeEnv = requestedEnv;
const emulatorPreference = (import.meta.env.VITE_USE_FIREBASE_EMULATORS ?? '').toLowerCase();
export const isUsingFirebaseEmulators =
  isLocalRuntime && emulatorPreference !== 'false';

let firebaseConfig: FirebaseClientConfig | null = null;
let firebaseInitError = '';

try {
  if (isLocalRuntime && !isUsingFirebaseEmulators && !allowProdOnLocal) {
    throw new Error(
      'Safety stop: localhost is attempting to use production Firebase. Run `npm run local` (recommended), set VITE_USE_FIREBASE_EMULATORS=true, or explicitly opt in with VITE_ALLOW_PROD_ON_LOCAL=true.'
    );
  }

  const configEnv: FirebaseRuntimeEnv = isUsingFirebaseEmulators ? 'prod' : activeFirebaseEnv;
  firebaseConfig = getFirebaseClientConfig(configEnv, import.meta.env);
} catch (error) {
  firebaseInitError =
    error instanceof Error ? error.message : 'Firebase configuration could not be loaded.';
}

const app = firebaseConfig ? initializeApp(firebaseConfig) : null;
let analytics: Analytics | null = null;
if (app && typeof window !== 'undefined') {
  try {
    analytics = getAnalytics(app);
  } catch (error) {
    console.warn("Firebase Analytics could not be initialized", error);
  }
}
const dbInstance = app ? getFirestore(app) : null;
const authInstance = app ? getAuth(app) : null;
const storageInstance = app ? getStorage(app) : null;

if (isUsingFirebaseEmulators && authInstance && dbInstance && storageInstance) {
  connectAuthEmulator(authInstance, `http://${emulatorHost}:9099`, { disableWarnings: true });
  connectFirestoreEmulator(dbInstance, emulatorHost, 8080);
  connectStorageEmulator(storageInstance, emulatorHost, 9199);
}

// Messaging setup (will be fully implemented in a later phase, requiring notification permissions)
let messaging: Messaging | null = null;
if (!isUsingFirebaseEmulators && app && typeof window !== 'undefined' && 'serviceWorker' in navigator) {
  // FCM relies on a complete browser environment for push notifications
  try {
    messaging = getMessaging(app);
  } catch (error) {
    console.warn("Firebase Messaging could not be initialized", error);
  }
}

const db = dbInstance as Firestore;
const auth = authInstance as Auth;
const storage = storageInstance as FirebaseStorage;

if (typeof window !== 'undefined') {
  (window as any).firebase_db = db;
  (window as any).firebase_auth = auth;
}

export { app, analytics, auth, db, firebaseConfig, firebaseInitError, storage, messaging };

import { createContext, useContext, useState, useEffect } from 'react';
import type { ReactNode } from 'react';
import type { User } from '../types/schema';
import { auth, db } from '../config/firebase';
import { onAuthStateChanged } from 'firebase/auth';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { inferRoleFromEmail, isOfflineLikeAuthError } from '../utils/auth';

interface AuthContextType {
  user: User | null;
  loading: boolean;
  setUser: (user: User | null) => void;
}

const AuthContext = createContext<AuthContextType>({} as AuthContextType);

// Using a placeholder mock until we attach proper Firestore mapping
export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const PROFILE_FETCH_TIMEOUT_MS = 2500;
    const AUTH_INIT_TIMEOUT_MS = 1500;
    let isActive = true;
    let authStateResolved = false;

    const buildFallbackUser = (firebaseUser: NonNullable<typeof auth.currentUser>): User => ({
      id: firebaseUser.uid,
      email: firebaseUser.email || '',
      role: inferRoleFromEmail(firebaseUser.email || '')
    });

    const withTimeout = async <T,>(promise: Promise<T>, timeoutMs: number): Promise<T> => {
      let timeoutId: ReturnType<typeof setTimeout>;
      const timeoutPromise = new Promise<never>((_, reject) => {
        timeoutId = setTimeout(() => reject(new Error('profile-fetch-timeout')), timeoutMs);
      });

      try {
        return await Promise.race([promise, timeoutPromise]);
      } finally {
        clearTimeout(timeoutId!);
      }
    };

    const authInitTimer = setTimeout(() => {
      if (!isActive || authStateResolved) {
        return;
      }

      authStateResolved = true;
      if (auth.currentUser) {
        console.warn('Auth state listener timed out; falling back to auth.currentUser.');
        setUser(buildFallbackUser(auth.currentUser));
      } else {
        setUser(null);
      }
      setLoading(false);
    }, AUTH_INIT_TIMEOUT_MS);

    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (!isActive) {
        return;
      }

      authStateResolved = true;
      clearTimeout(authInitTimer);

      if (firebaseUser) {
        const fallbackUser = buildFallbackUser(firebaseUser);

        // Let routing continue immediately after Firebase Auth confirms the session.
        setUser(fallbackUser);
        setLoading(false);

        try {
          const isOffline = typeof navigator !== 'undefined' && navigator.onLine === false;
          if (isOffline) {
            return;
          } else {
            const userDoc = await withTimeout(
              getDoc(doc(db, 'users', firebaseUser.uid)),
              PROFILE_FETCH_TIMEOUT_MS
            );
            if (!isActive) {
              return;
            }

            if (userDoc.exists()) {
              const data = userDoc.data();
              const inferredRole = fallbackUser.role; // from email
              const isParentUser = inferredRole === 'parent_admin';

              // Self-heal: fix missing/incorrect role or empty linked_family_id.
              // Uses isSelf permission which always works regardless of the role field.
              const needsRoleHeal = isParentUser && data.role !== 'parent_admin' && data.role !== 'parent';
              const needsFamilyIdHeal = isParentUser && (!data.linked_family_id || data.linked_family_id === '');

              if (needsRoleHeal || needsFamilyIdHeal) {
                const healPayload: Record<string, string> = { updated_at: new Date().toISOString() };
                if (needsRoleHeal) healPayload.role = 'parent_admin';
                if (needsFamilyIdHeal) healPayload.linked_family_id = firebaseUser.uid;
                // Fire-and-forget — don't block user from continuing
                setDoc(doc(db, 'users', firebaseUser.uid), healPayload, { merge: true }).catch(
                  (e) => console.warn('Self-heal of user doc failed (non-fatal):', e)
                );
              }

              setUser({
                id: firebaseUser.uid,
                email: firebaseUser.email || '',
                role: (needsRoleHeal ? 'parent_admin' : data.role) ?? fallbackUser.role,
                parent_id: data.parent_id,
                linked_family_id: needsFamilyIdHeal ? firebaseUser.uid : (data.linked_family_id || undefined)
              });
            } else {
              // Safeguard fallback if document creation lagged.
              setUser(fallbackUser);
              const isParent = fallbackUser.role === 'parent_admin';
              await setDoc(doc(db, 'users', firebaseUser.uid), {
                id: firebaseUser.uid,
                email: firebaseUser.email || '',
                role: fallbackUser.role,
                ...(isParent ? { linked_family_id: firebaseUser.uid } : {}),
                updated_at: new Date().toISOString()
              }, { merge: true });
            }
          }
        } catch (error) {
          if (!isActive) {
            return;
          }

          // Keep authenticated users signed in even if Firestore profile read fails.
          const offline = isOfflineLikeAuthError(error);
          const logger = offline ? console.warn : console.error;
          logger("Auth profile fetch failed; using auth fallback:", error);
          setUser(fallbackUser);
        }
      } else {
        setUser(null);
        setLoading(false);
      }
    });

    return () => {
      isActive = false;
      clearTimeout(authInitTimer);
      unsubscribe();
    };
  }, []);

  return (
    <AuthContext.Provider value={{ user, loading, setUser }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import type { ReactNode } from 'react';
import { db } from '../config/firebase';
import {
  collection,
  doc,
  onSnapshot,
  query,
  where,
  orderBy,
  addDoc,
  updateDoc,
  serverTimestamp,
} from 'firebase/firestore';
import type { Task, Challenge } from '../types/schema';

interface RealTimeMessage {
  id: string;
  type: 'task_completed' | 'challenge_update' | 'inbox_message' | 'achievement' | 'reminder';
  title: string;
  message: string;
  data?: any;
  timestamp: Date;
  read: boolean;
}

interface RealTimeContextType {
  // Real-time data
  liveTasks: Task[];
  liveChallenges: Challenge[];
  liveMessages: RealTimeMessage[];
  unreadCount: number;

  // Connection status
  isConnected: boolean;
  connectionStatus: 'connecting' | 'connected' | 'disconnected' | 'error';

  // Actions
  markMessageAsRead: (messageId: string) => Promise<void>;
  sendRealTimeMessage: (type: RealTimeMessage['type'], title: string, message: string, data?: any) => Promise<void>;
  subscribeToChild: (childId: string) => void;
  unsubscribeFromChild: () => void;

  // Performance metrics
  lastUpdate: Date | null;
  updateCount: number;
}

const RealTimeContext = createContext<RealTimeContextType | undefined>(undefined);

interface RealTimeProviderProps {
  children: ReactNode;
  userId?: string;
  userRole?: 'parent_admin' | 'child_user';
  childId?: string; // For child-specific subscriptions
}

export const RealTimeProvider: React.FC<RealTimeProviderProps> = ({
  children,
  userId = '',
  userRole = 'child_user',
  childId,
}) => {
  const [liveTasks, setLiveTasks] = useState<Task[]>([]);
  const [liveChallenges, setLiveChallenges] = useState<Challenge[]>([]);
  const [liveMessages, setLiveMessages] = useState<RealTimeMessage[]>([]);
  const [isConnected, setIsConnected] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'disconnected' | 'error'>('connecting');
  const [lastUpdate, setLastUpdate] = useState<Date | null>(null);
  const [updateCount, setUpdateCount] = useState(0);

  // Unsubscribe functions
  const [taskUnsubscribe, setTaskUnsubscribe] = useState<(() => void) | null>(null);
  const [challengeUnsubscribe, setChallengeUnsubscribe] = useState<(() => void) | null>(null);
  const [messageUnsubscribe, setMessageUnsubscribe] = useState<(() => void) | null>(null);

  // Calculate unread messages count
  const unreadCount = liveMessages.filter(msg => !msg.read).length;

  // Mark message as read
  const markMessageAsRead = useCallback(async (messageId: string) => {
    try {
      const messageRef = doc(db, 'realtime_messages', messageId);
      await updateDoc(messageRef, {
        read: true,
        read_at: serverTimestamp(),
      });
    } catch (error) {
      console.error('Error marking message as read:', error);
    }
  }, []);

  // Send real-time message
  const sendRealTimeMessage = useCallback(async (
    type: RealTimeMessage['type'],
    title: string,
    message: string,
    data?: any
  ) => {
    try {
      await addDoc(collection(db, 'realtime_messages'), {
        type,
        title,
        message,
        data,
        timestamp: serverTimestamp(),
        read: false,
        user_id: userId,
        user_role: userRole,
        child_id: childId,
      });
    } catch (error) {
      console.error('Error sending real-time message:', error);
    }
  }, [userId, userRole, childId]);

  // Subscribe to tasks
  const subscribeToTasks = useCallback((targetChildId: string) => {
    if (taskUnsubscribe) {
      taskUnsubscribe();
    }

    const tasksQuery = query(
      collection(db, 'tasks'),
      where('child_id', '==', targetChildId),
      orderBy('created_at', 'desc'),
      // Limit to recent tasks for performance
    );

    const unsubscribe = onSnapshot(
      tasksQuery,
      (snapshot) => {
        const tasks = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        } as Task));

        setLiveTasks(tasks);
        setLastUpdate(new Date());
        setUpdateCount(prev => prev + 1);
        setIsConnected(true);
        setConnectionStatus('connected');
      },
      (error) => {
        console.error('Tasks subscription error:', error);
        setConnectionStatus('error');
        setIsConnected(false);
      }
    );

    setTaskUnsubscribe(() => unsubscribe);
  }, [taskUnsubscribe]);

  // Subscribe to challenges
  const subscribeToChallenges = useCallback((targetChildId: string) => {
    if (challengeUnsubscribe) {
      challengeUnsubscribe();
    }

    const challengesQuery = query(
      collection(db, 'challenges'),
      where(userRole === 'parent_admin' ? 'parent_id' : 'child_id', '==', userId),
      where('child_id', '==', targetChildId),
      orderBy('created_at', 'desc')
    );

    const unsubscribe = onSnapshot(
      challengesQuery,
      (snapshot) => {
        const challenges = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        } as Challenge));

        setLiveChallenges(challenges);
        setLastUpdate(new Date());
        setUpdateCount(prev => prev + 1);
      },
      (error) => {
        console.error('Challenges subscription error:', error);
        setConnectionStatus('error');
      }
    );

    setChallengeUnsubscribe(() => unsubscribe);
  }, [challengeUnsubscribe, userId, userRole]);

  // Subscribe to real-time messages
  const subscribeToMessages = useCallback(() => {
    if (messageUnsubscribe) {
      messageUnsubscribe();
    }

    let messagesQuery;
    if (userRole === 'parent_admin') {
      // Parents see messages for all their children
      messagesQuery = query(
        collection(db, 'realtime_messages'),
        where('user_id', '==', userId),
        orderBy('timestamp', 'desc')
      );
    } else {
      // Children see their own messages
      messagesQuery = query(
        collection(db, 'realtime_messages'),
        where('child_id', '==', childId),
        orderBy('timestamp', 'desc')
      );
    }

    const unsubscribe = onSnapshot(
      messagesQuery,
      (snapshot) => {
        const messages = snapshot.docs.map(doc => {
          const data = doc.data();
          return {
            id: doc.id,
            type: data.type,
            title: data.title,
            message: data.message,
            data: data.data,
            timestamp: data.timestamp?.toDate() || new Date(),
            read: data.read || false,
          } as RealTimeMessage;
        });

        setLiveMessages(messages);
        setLastUpdate(new Date());
        setUpdateCount(prev => prev + 1);
      },
      (error) => {
        console.error('Messages subscription error:', error);
        setConnectionStatus('error');
      }
    );

    setMessageUnsubscribe(() => unsubscribe);
  }, [messageUnsubscribe, userId, userRole, childId]);

  // Subscribe to specific child
  const subscribeToChild = useCallback((targetChildId: string) => {
    setConnectionStatus('connecting');
    setIsConnected(false);

    subscribeToTasks(targetChildId);
    subscribeToChallenges(targetChildId);
    subscribeToMessages();

    setIsConnected(true);
    setConnectionStatus('connected');
  }, [subscribeToTasks, subscribeToChallenges, subscribeToMessages]);

  // Unsubscribe from child
  const unsubscribeFromChild = useCallback(() => {
    if (taskUnsubscribe) {
      taskUnsubscribe();
      setTaskUnsubscribe(null);
    }
    if (challengeUnsubscribe) {
      challengeUnsubscribe();
      setChallengeUnsubscribe(null);
    }
    if (messageUnsubscribe) {
      messageUnsubscribe();
      setMessageUnsubscribe(null);
    }

    setLiveTasks([]);
    setLiveChallenges([]);
    setLiveMessages([]);
    setIsConnected(false);
    setConnectionStatus('disconnected');
  }, [taskUnsubscribe, challengeUnsubscribe, messageUnsubscribe]);

  // Auto-subscribe on mount if childId provided
  useEffect(() => {
    if (childId) {
      subscribeToChild(childId);
    }

    return () => {
      unsubscribeFromChild();
    };
  }, [childId, subscribeToChild, unsubscribeFromChild]);

  // Connection health check
  useEffect(() => {
    const healthCheck = setInterval(() => {
      if (isConnected && lastUpdate) {
        const timeSinceLastUpdate = Date.now() - lastUpdate.getTime();
        if (timeSinceLastUpdate > 30000) { // 30 seconds
          setConnectionStatus('disconnected');
          setIsConnected(false);
        }
      }
    }, 10000); // Check every 10 seconds

    return () => clearInterval(healthCheck);
  }, [isConnected, lastUpdate]);

  const contextValue: RealTimeContextType = {
    liveTasks,
    liveChallenges,
    liveMessages,
    unreadCount,
    isConnected,
    connectionStatus,
    markMessageAsRead,
    sendRealTimeMessage,
    subscribeToChild,
    unsubscribeFromChild,
    lastUpdate,
    updateCount,
  };

  return (
    <RealTimeContext.Provider value={contextValue}>
      {children}
    </RealTimeContext.Provider>
  );
};

export const useRealTime = (): RealTimeContextType => {
  const context = useContext(RealTimeContext);
  if (context === undefined) {
    throw new Error('useRealTime must be used within a RealTimeProvider');
  }
  return context;
};

// Hook for sending automated real-time notifications
export const useRealTimeNotifications = () => {
  const { sendRealTimeMessage } = useRealTime();

  const notifyTaskCompleted = useCallback(async (task: Task, childName: string) => {
    await sendRealTimeMessage(
      'task_completed',
      '🎉 Task Completed!',
      `${childName} completed "${task.title}" and earned ${task.star_value} stars!`,
      { task_id: task.id, stars_earned: task.star_value }
    );
  }, [sendRealTimeMessage]);

  const notifyChallengeUpdate = useCallback(async (challenge: Challenge, childName: string) => {
    const statusMessage = challenge.status === 'completed' ? 'completed' : 'updated';
    await sendRealTimeMessage(
      'challenge_update',
      '🏆 Challenge Update',
      `${childName} ${statusMessage} the challenge "${challenge.title}"!`,
      { challenge_id: challenge.id, status: challenge.status }
    );
  }, [sendRealTimeMessage]);

  const notifyAchievement = useCallback(async (achievement: string, childName: string, data?: any) => {
    await sendRealTimeMessage(
      'achievement',
      '⭐ Achievement Unlocked!',
      `${childName} unlocked: ${achievement}`,
      data
    );
  }, [sendRealTimeMessage]);

  const notifyReminder = useCallback(async (reminderTitle: string, childName: string) => {
    await sendRealTimeMessage(
      'reminder',
      '🔔 Reminder',
      reminderTitle,
      { child_name: childName }
    );
  }, [sendRealTimeMessage]);

  return {
    notifyTaskCompleted,
    notifyChallengeUpdate,
    notifyAchievement,
    notifyReminder,
  };
};

import { createContext, useContext, useEffect, useMemo, useState } from 'react';
import type { ReactNode } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextType {
  theme: Theme;
  toggleTheme: () => void;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType>({} as ThemeContextType);

const THEME_STORAGE_KEY = 'tiktrack-theme';

export function ThemeProvider({ children }: { children: ReactNode }) {
  const [theme, setThemeState] = useState<Theme>('light');

  useEffect(() => {
    const saved = localStorage.getItem(THEME_STORAGE_KEY) as Theme | null;
    if (saved === 'light' || saved === 'dark') {
      setThemeState(saved);
      return;
    }

    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
    setThemeState(prefersDark ? 'dark' : 'light');
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem(THEME_STORAGE_KEY, theme);
  }, [theme]);

  const value = useMemo(
    () => ({
      theme,
      toggleTheme: () => setThemeState((prev) => (prev === 'light' ? 'dark' : 'light')),
      setTheme: (next: Theme) => setThemeState(next)
    }),
    [theme]
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export const useTheme = () => useContext(ThemeContext);

import React, { createContext, useCallback, useContext, useReducer } from 'react';

// ── Types ────────────────────────────────────────────────────────────────────

export type ToastType = 'success' | 'error' | 'info' | 'warning';

export interface Toast {
  id: string;
  message: string;
  type: ToastType;
  duration: number; // ms
}

interface ToastContextValue {
  addToast: (message: string, type?: ToastType, duration?: number) => void;
}

// ── Context ──────────────────────────────────────────────────────────────────

const ToastContext = createContext<ToastContextValue | null>(null);

// ── Reducer ──────────────────────────────────────────────────────────────────

type Action =
  | { type: 'ADD'; toast: Toast }
  | { type: 'REMOVE'; id: string };

function reducer(state: Toast[], action: Action): Toast[] {
  switch (action.type) {
    case 'ADD':
      return [action.toast, ...state].slice(0, 5); // max 5 stacked
    case 'REMOVE':
      return state.filter((t) => t.id !== action.id);
    default:
      return state;
  }
}

// ── Icons ────────────────────────────────────────────────────────────────────

function ToastIcon({ type }: { type: ToastType }) {
  if (type === 'success') {
    return (
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M22 11.08V12a10 10 0 1 1-5.93-9.14" /><polyline points="22 4 12 14.01 9 11.01" />
      </svg>
    );
  }
  if (type === 'error') {
    return (
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
        <circle cx="12" cy="12" r="10" /><line x1="15" y1="9" x2="9" y2="15" /><line x1="9" y1="9" x2="15" y2="15" />
      </svg>
    );
  }
  if (type === 'warning') {
    return (
      <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z" /><line x1="12" y1="9" x2="12" y2="13" /><line x1="12" y1="17" x2="12.01" y2="17" />
      </svg>
    );
  }
  // info
  return (
    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="12" cy="12" r="10" /><line x1="12" y1="16" x2="12" y2="12" /><line x1="12" y1="8" x2="12.01" y2="8" />
    </svg>
  );
}

// ── Toast Item Component ──────────────────────────────────────────────────────

const TOAST_STYLES: Record<ToastType, { bg: string; border: string; icon: string; bar: string }> = {
  success: {
    bg: 'bg-[#0f2818]/95',
    border: 'border-emerald-500/40',
    icon: 'text-emerald-400',
    bar: 'bg-emerald-400',
  },
  error: {
    bg: 'bg-[#1f0a0a]/95',
    border: 'border-rose-500/40',
    icon: 'text-rose-400',
    bar: 'bg-rose-400',
  },
  warning: {
    bg: 'bg-[#1f1505]/95',
    border: 'border-amber-500/40',
    icon: 'text-amber-400',
    bar: 'bg-amber-400',
  },
  info: {
    bg: 'bg-[#080f1f]/95',
    border: 'border-cyan-500/40',
    icon: 'text-cyan-400',
    bar: 'bg-cyan-400',
  },
};

function ToastItem({ toast, onRemove }: { toast: Toast; onRemove: (id: string) => void }) {
  const [visible, setVisible] = React.useState(false);
  const [leaving, setLeaving] = React.useState(false);
  const style = TOAST_STYLES[toast.type];

  // Enter animation
  React.useEffect(() => {
    const frame = requestAnimationFrame(() => setVisible(true));
    return () => cancelAnimationFrame(frame);
  }, []);

  // Auto-dismiss
  React.useEffect(() => {
    const dismissTimer = setTimeout(() => {
      setLeaving(true);
      setTimeout(() => onRemove(toast.id), 350);
    }, toast.duration);
    return () => clearTimeout(dismissTimer);
  }, [toast.duration, toast.id, onRemove]);

  const handleClose = () => {
    setLeaving(true);
    setTimeout(() => onRemove(toast.id), 350);
  };

  return (
    <div
      className={`
        relative overflow-hidden w-80 max-w-[calc(100vw-2rem)] rounded-2xl border backdrop-blur-xl shadow-2xl
        transition-all duration-350 ease-out
        ${style.bg} ${style.border}
        ${visible && !leaving ? 'translate-x-0 opacity-100' : 'translate-x-full opacity-0'}
      `}
    >
      {/* Content */}
      <div className="flex items-start gap-3 px-4 py-3.5">
        <span className={`mt-0.5 flex-shrink-0 ${style.icon}`}>
          <ToastIcon type={toast.type} />
        </span>
        <p className="flex-1 text-sm font-semibold text-white/90 leading-5">{toast.message}</p>
        <button
          type="button"
          onClick={handleClose}
          className="flex-shrink-0 mt-0.5 text-white/30 hover:text-white/70 transition-colors"
          aria-label="Dismiss"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
            <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
          </svg>
        </button>
      </div>

      {/* Progress bar */}
      <div className="absolute bottom-0 left-0 right-0 h-[2px] bg-white/5">
        <div
          className={`h-full ${style.bar} origin-left`}
          style={{
            animation: `toast-progress ${toast.duration}ms linear forwards`,
          }}
        />
      </div>

      <style>{`
        @keyframes toast-progress {
          from { transform: scaleX(1); }
          to { transform: scaleX(0); }
        }
      `}</style>
    </div>
  );
}

// ── Provider ─────────────────────────────────────────────────────────────────

export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toasts, dispatch] = useReducer(reducer, []);

  const addToast = useCallback(
    (message: string, type: ToastType = 'info', duration = 5000) => {
      const id = `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`;
      dispatch({ type: 'ADD', toast: { id, message, type, duration } });
    },
    []
  );

  const removeToast = useCallback((id: string) => {
    dispatch({ type: 'REMOVE', id });
  }, []);

  return (
    <ToastContext.Provider value={{ addToast }}>
      {children}

      {/* Toast Stack — fixed top-right */}
      <div
        aria-live="polite"
        aria-label="Notifications"
        className="fixed top-4 right-4 z-[200] flex flex-col gap-2 pointer-events-none"
      >
        {toasts.map((toast) => (
          <div key={toast.id} className="pointer-events-auto">
            <ToastItem toast={toast} onRemove={removeToast} />
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

// ── Hook ─────────────────────────────────────────────────────────────────────

export function useToast() {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error('useToast must be used within <ToastProvider>');
  return ctx;
}

import { useEffect, useMemo, useState } from 'react';
import { PLANNER_EVENT_CATEGORIES } from '../../constants/planner.constants';
import type { PlannerEvent, PlannerProgram } from '../../types/planner.types';
import { plannerEventInputSchema, type PlannerEventInput } from '../../utils/planner.validation';
import { useUnsavedChangesGuard } from '../../hooks/useUnsavedChangesGuard';

const WEEK_DAYS = [
  { id: 0, label: 'Sun' },
  { id: 1, label: 'Mon' },
  { id: 2, label: 'Tue' },
  { id: 3, label: 'Wed' },
  { id: 4, label: 'Thu' },
  { id: 5, label: 'Fri' },
  { id: 6, label: 'Sat' }
];

interface ParentEventEditorModalProps {
  open: boolean;
  mode: 'create' | 'edit';
  event: PlannerEvent | null;
  programs: PlannerProgram[];
  onClose: () => void;
  onSubmit: (input: PlannerEventInput) => Promise<void>;
}

function toInputDateTimeLocal(value: string): string {
  const d = new Date(value);
  const offset = d.getTimezoneOffset();
  const local = new Date(d.getTime() - offset * 60000);
  return local.toISOString().slice(0, 16);
}

function toIsoFromLocal(value: string): string {
  const d = new Date(value);
  return d.toISOString();
}

export function ParentEventEditorModal({ open, mode, event, programs, onClose, onSubmit }: ParentEventEditorModalProps) {
  const draftKey = useMemo(() => `planner_event_draft_${mode}_${event?.id || 'new'}`, [event?.id, mode]);
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<PlannerEvent['category']>('school');
  const [startAt, setStartAt] = useState('');
  const [endAt, setEndAt] = useState('');
  const [linkedProgramId, setLinkedProgramId] = useState('');
  const [recurrenceType, setRecurrenceType] = useState<'none' | 'daily' | 'weekly'>('none');
  const [recurrenceWeekDays, setRecurrenceWeekDays] = useState<number[]>([]);
  const [error, setError] = useState('');
  const [saving, setSaving] = useState(false);
  const [initialSnapshot, setInitialSnapshot] = useState('');

  useEffect(() => {
    if (!open) return;

    const saved = localStorage.getItem(draftKey);
    if (saved) {
      try {
        const parsed = JSON.parse(saved) as {
          title: string;
          category: PlannerEvent['category'];
          startAt: string;
          endAt: string;
          linkedProgramId: string;
          recurrenceType: 'none' | 'daily' | 'weekly';
          recurrenceWeekDays: number[];
        };
        setTitle(parsed.title || '');
        setCategory(parsed.category || 'school');
        setStartAt(parsed.startAt || '');
        setEndAt(parsed.endAt || '');
        setLinkedProgramId(parsed.linkedProgramId || '');
        setRecurrenceType(parsed.recurrenceType || 'none');
        setRecurrenceWeekDays(parsed.recurrenceWeekDays || []);
        setInitialSnapshot(saved);
        return;
      } catch {
      }
    }

    if (event) {
      setTitle(event.title);
      setCategory(event.category);
      setStartAt(toInputDateTimeLocal(event.startAt));
      setEndAt(toInputDateTimeLocal(event.endAt));
      setLinkedProgramId(event.linkedProgramId || '');
      const recurrence = event.recurrence.type;
      setRecurrenceType(recurrence === 'daily' || recurrence === 'weekly' ? recurrence : 'none');
      setRecurrenceWeekDays(event.recurrence.byWeekDays || []);
      setInitialSnapshot(JSON.stringify({ title: event.title, category: event.category, startAt: toInputDateTimeLocal(event.startAt), endAt: toInputDateTimeLocal(event.endAt), linkedProgramId: event.linkedProgramId || '', recurrenceType: recurrence === 'daily' || recurrence === 'weekly' ? recurrence : 'none', recurrenceWeekDays: event.recurrence.byWeekDays || [] }));
    } else {
      const start = new Date();
      start.setHours(start.getHours() + 1, 0, 0, 0);
      const end = new Date(start.getTime() + 60 * 60000);
      setTitle('');
      setCategory('school');
      setStartAt(toInputDateTimeLocal(start.toISOString()));
      setEndAt(toInputDateTimeLocal(end.toISOString()));
      setLinkedProgramId('');
      setRecurrenceType('none');
      setRecurrenceWeekDays([]);
      setInitialSnapshot(JSON.stringify({ title: '', category: 'school', startAt: toInputDateTimeLocal(start.toISOString()), endAt: toInputDateTimeLocal(end.toISOString()), linkedProgramId: '', recurrenceType: 'none', recurrenceWeekDays: [] }));
    }
  }, [draftKey, event, open]);

  useEffect(() => {
    if (!open) return;
    localStorage.setItem(draftKey, JSON.stringify({ title, category, startAt, endAt, linkedProgramId, recurrenceType, recurrenceWeekDays }));
  }, [category, draftKey, endAt, linkedProgramId, open, recurrenceType, recurrenceWeekDays, startAt, title]);

  const currentSnapshot = JSON.stringify({ title, category, startAt, endAt, linkedProgramId, recurrenceType, recurrenceWeekDays });
  const hasUnsavedChanges = open && currentSnapshot !== initialSnapshot;
  useUnsavedChangesGuard(hasUnsavedChanges);

  function handleCloseRequest() {
    if (hasUnsavedChanges && !window.confirm('Discard unsaved changes?')) return;
    onClose();
  }

  if (!open) return null;

  async function handleSubmit() {
    setError('');
    const parsed = plannerEventInputSchema.safeParse({
      title,
      category,
      startAt: toIsoFromLocal(startAt),
      endAt: toIsoFromLocal(endAt),
      linkedProgramId: linkedProgramId || null,
      recurrenceType,
      recurrenceWeekDays
    });

    if (!parsed.success) {
      setError(parsed.error.issues[0]?.message || 'Invalid event data');
      return;
    }

    setSaving(true);
    try {
      await onSubmit(parsed.data);
      localStorage.removeItem(draftKey);
      onClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to save event');
    } finally {
      setSaving(false);
    }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/50 p-4 md:items-center" role="dialog" aria-modal="true">
      <div className="w-full max-w-xl rounded-3xl border border-white/10 bg-slate-950 p-5 shadow-2xl max-h-[85vh] overflow-auto">
        <div className="flex items-start justify-between gap-3">
          <h3 className="text-lg font-bold text-white">{mode === 'create' ? 'Create Event' : 'Edit Event'}</h3>
          <button type="button" onClick={handleCloseRequest} className="min-h-[40px] rounded-lg border border-white/15 px-2.5 py-1 text-xs text-white/70 focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300">Close</button>
        </div>

        <div className="mt-4 space-y-3">
          <input aria-label="Event title" value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Title" className="min-h-[44px] w-full rounded-xl border border-white/15 bg-white/[0.04] px-3 py-2 text-sm text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300" />

          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
            <select aria-label="Event category" value={category} onChange={(e) => setCategory(e.target.value as PlannerEvent['category'])} className="min-h-[44px] rounded-xl border border-white/15 bg-white/[0.04] px-3 py-2 text-sm text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300">
              {PLANNER_EVENT_CATEGORIES.map((cat) => <option key={cat} value={cat}>{cat.replace('_', ' ')}</option>)}
            </select>
            <select aria-label="Linked program" value={linkedProgramId} onChange={(e) => setLinkedProgramId(e.target.value)} className="min-h-[44px] rounded-xl border border-white/15 bg-white/[0.04] px-3 py-2 text-sm text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300">
              <option value="">No linked program</option>
              {programs.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>

          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
            <input aria-label="Start date and time" type="datetime-local" value={startAt} onChange={(e) => setStartAt(e.target.value)} className="min-h-[44px] rounded-xl border border-white/15 bg-white/[0.04] px-3 py-2 text-sm text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300" />
            <input aria-label="End date and time" type="datetime-local" value={endAt} onChange={(e) => setEndAt(e.target.value)} className="min-h-[44px] rounded-xl border border-white/15 bg-white/[0.04] px-3 py-2 text-sm text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300" />
          </div>

          <div>
            <select aria-label="Recurrence type" value={recurrenceType} onChange={(e) => setRecurrenceType(e.target.value as 'none' | 'daily' | 'weekly')} className="min-h-[44px] w-full rounded-xl border border-white/15 bg-white/[0.04] px-3 py-2 text-sm text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-cyan-300">
              <option value="none">No recurrence</option>
              <option value="daily">Daily</option>
              <option value="weekly">Weekly</option>
            </select>
            {recurrenceType === 'weekly' ? (
              <div className="mt-2 flex flex-wrap gap-2">
                {WEEK_DAYS.map((day) => {
                  const active = recurrenceWeekDays.includes(day.id);
                  return (
                    <button
                      key={day.id}
                      type="button"
                      onClick={() => setRecurrenceWeekDays((prev) => (prev.includes(day.id) ? prev.filter((x) => x !== day.id) : [...prev, day.id]))}
                      className={active ? 'rounded-full border border-cyan-300/40 bg-cyan-400/20 px-3 py-1 text-xs text-cyan-100' : 'rounded-full border border-white/15 bg-white/5 px-3 py-1 text-xs text-white/70'}
                    >
                      {day.label}
                    </button>
                  );
                })}
              </div>
            ) : null}
          </div>

          {error ? <p className="text-sm text-rose-300">{error}</p> : null}

          <button type="button" disabled={saving} onClick={() => void handleSubmit()} className="w-full rounded-xl bg-cyan-500/30 px-4 py-2 text-sm font-semibold text-cyan-100 disabled:opacity-60">
            {saving ? 'Saving...' : mode === 'create' ? 'Create event' : 'Save changes'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { collection, query, where, onSnapshot, addDoc, updateDoc, doc, deleteDoc, getDoc } from 'firebase/firestore';
import { db } from '../../../config/firebase';
import type { Challenge } from '../../../types/schema';

export function usePlannerChallenges(childId: string, programId?: string | null, challengePoints?: number | null) {
  const [challenges, setChallenges] = useState<Challenge[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!childId) {
      setChallenges([]);
      setLoading(false);
      return;
    }

    let q = query(collection(db, 'challenges'), where('child_id', '==', childId));

    // If we have a programId, we could filter by it, but maybe we want to see all challenges for this child?
    // User said "under an activity", so filtering by programId is appropriate.
    if (programId) {
      q = query(collection(db, 'challenges'), where('child_id', '==', childId), where('linked_program_id', '==', programId));
    }

    const unsubscribe = onSnapshot(
      q,
      (snap) => {
        const mapped = snap.docs
          .map((d) => ({ id: d.id, ...(d.data() as Omit<Challenge, 'id'>) }))
          .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
        setChallenges(mapped);
        setLoading(false);
      },
      (error) => {
        console.warn('usePlannerChallenges failed:', error);
        setChallenges([]);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, [childId, programId]);

  const createChallenge = useCallback(async (
    title: string,
    parentId: string,
    targetScore: number,
    description?: string
  ) => {
    await addDoc(collection(db, 'challenges'), {
      title,
      description: description || '',
      parent_id: parentId,
      child_id: childId,
      parent_score: 0,
      child_score: 0,
      target_score: targetScore,
      status: 'active',
      linked_program_id: programId || null,
      created_at: new Date().toISOString()
    });
  }, [childId, programId]);

  const incrementScore = useCallback(async (challengeId: string, who: 'parent' | 'child') => {
    const challenge = challenges.find(c => c.id === challengeId);
    if (!challenge || challenge.status === 'completed') return;

    const field = who === 'parent' ? 'parent_score' : 'child_score';
    const newScore = (who === 'parent' ? challenge.parent_score : challenge.child_score) + 1;

    const updates: Record<string, any> = { 
      [field]: newScore,
      updated_at: new Date().toISOString()
    };

    if (newScore >= challenge.target_score) {
      updates.status = 'completed';
      updates.completed_at = new Date().toISOString();
      updates.winner = who;
    }

    await updateDoc(doc(db, 'challenges', challengeId), updates);

    // Award stars if challenge is now complete and points are configured
    if (newScore >= challenge.target_score && challengePoints && challengePoints > 0 && childId) {
      const profileRef = doc(db, 'child_profile', childId);
      const profileSnap = await getDoc(profileRef);
      if (profileSnap.exists()) {
        const currentStars = profileSnap.data().total_stars || 0;
        await updateDoc(profileRef, {
          total_stars: currentStars + challengePoints
        });
      }
    }
  }, [challenges, challengePoints, childId]);

  const deleteChallenge = useCallback(async (challengeId: string) => {
    await deleteDoc(doc(db, 'challenges', challengeId));
  }, []);

  return {
    challenges,
    loading,
    createChallenge,
    incrementScore,
    deleteChallenge
  };
}

import { useEffect, useMemo, useState } from 'react';
import { collection, onSnapshot, query, where } from 'firebase/firestore';
import { db } from '../../../config/firebase';
import { MOCK_PLANNER_EVENTS } from '../constants/planner.mock';
import { mapPlannerEvent } from '../services/planner.firestore';
import type { PlannerDateRange, PlannerEvent } from '../types/planner.types';
import { useAuth } from '../../../contexts/AuthContext';

export function usePlannerEvents(childId: string, range?: PlannerDateRange, useMockFallback = true) {
  const { user } = useAuth();
  const familyId = user?.linked_family_id || user?.id || '';
  const [events, setEvents] = useState<PlannerEvent[]>([]);
  const [taskEvents, setTaskEvents] = useState<PlannerEvent[]>([]);
  const [examEvents, setExamEvents] = useState<PlannerEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const effectiveRange = useMemo(() => range || null, [range?.endAt, range?.startAt]);

  useEffect(() => {
    if (!childId || !familyId) {
      setEvents(useMockFallback ? MOCK_PLANNER_EVENTS : []);
      setLoading(false);
      return;
    }

    setLoading(true);

    // 1. Real-time events query. When no range is supplied, keep all program
    // events available so activity-level month navigation can look backward.
    const eventsQuery = effectiveRange
      ? query(
          collection(db, 'events'),
          where('family_id', '==', familyId),
          where('start_at', '>=', effectiveRange.startAt),
          where('start_at', '<=', effectiveRange.endAt)
        )
      : query(collection(db, 'events'), where('family_id', '==', familyId));

    const unsubEvents = onSnapshot(
      eventsQuery,
      (snap) => {
        const rows = snap.docs.map((docRow) =>
          mapPlannerEvent(docRow.id, docRow.data() as Record<string, unknown>)
        );
        const filteredRows = rows.filter(e => !e.childId || e.childId === childId);
        if (filteredRows.length === 0 && useMockFallback) {
          setEvents(MOCK_PLANNER_EVENTS.map((event) => ({ ...event, childId })));
        } else {
          setEvents(filteredRows);
        }
        setLoading(false);
      },
      (err) => {
        console.error('Events real-time query failed:', err);
        setEvents(useMockFallback ? MOCK_PLANNER_EVENTS.map((event) => ({ ...event, childId })) : []);
        setLoading(false);
      }
    );

    // 2. Real-time tasks query
    const taskQuery = query(collection(db, 'tasks'), where('child_id', '==', childId));
    const unsubTasks = onSnapshot(
      taskQuery,
      (snap) => {
        const now = new Date().toISOString();
        const mappedTasks: PlannerEvent[] = snap.docs.map((d) => {
          const row = d.data() as Record<string, unknown>;
          let baseStart = now;
          if (typeof row.available_from === 'string') {
            baseStart = row.available_from;
          } else if (typeof row.due_date === 'string') {
            baseStart = row.due_date;
          } else if (typeof row.end_date === 'string') {
            baseStart = row.end_date;
          }
          let endAt = baseStart;
          if (typeof row.expires_at === 'string') {
            endAt = row.expires_at;
          } else if (typeof row.end_date === 'string') {
            endAt = row.end_date;
          }
          return {
            id: `task_${d.id}`,
            familyId,
            childId,
            parentId: familyId,
            title: String(row.title || 'Task'),
            category: 'homework',
            color: '#eab308',
            startAt: baseStart,
            endAt: endAt,
            allDay: true,
            timezone: 'Asia/Kolkata',
            recurrence: {
              type: ((row.recurrence_type || 'none') as any),
              interval: 1,
              byWeekDays: (Array.isArray(row.recurrence_days) ? row.recurrence_days : []),
              byMonthDays: [],
              until: null,
              count: null,
              rrule: null
            },
            taskStatus: (row.status as string) || 'pending',
            taskApprovalStatus: (row.approval_status as string) || 'none',
            taskPoints: typeof row.star_value === 'number' ? row.star_value : (typeof row.points === 'number' ? row.points : 0),
            linkedProgramId: (row.linked_program_id as string) || null,
            subjectId: (row.subject_id as string) || null,
            linkedTaskIds: [d.id],
            participantIds: [],
            reminderIds: [],
            source: 'manual',
            sync: { googleEnabled: false, googleEventId: null, syncStatus: 'not_configured', lastSyncAt: null, syncError: null },
            createdBy: 'child',
            createdAt: now,
            updatedAt: now,
            deletedAt: null
          };
        });
        setTaskEvents(mappedTasks);
      },
      (err) => {
        console.warn('Real-time tasks stream failed:', err);
      }
    );

    // 3. Real-time exams query
    const examQuery = query(collection(db, 'exams'), where('child_id', '==', childId));
    const unsubExams = onSnapshot(
      examQuery,
      (snap) => {
        const now = new Date().toISOString();
        const mappedExams: PlannerEvent[] = snap.docs.map((d) => {
          const row = d.data() as Record<string, unknown>;
          let startAt = now;
          let endAt = now;
          if (typeof row.exam_date === 'string') {
            const isIso = row.exam_date.includes('T');
            startAt = isIso ? row.exam_date : `${row.exam_date}T09:00:00.000Z`;
            endAt = isIso ? row.exam_date : `${row.exam_date}T11:00:00.000Z`;
          } else if (typeof row.date === 'string') {
            const isIso = row.date.includes('T');
            startAt = isIso ? row.date : `${row.date}T09:00:00.000Z`;
            endAt = isIso ? row.date : `${row.date}T11:00:00.000Z`;
          }

          const marksScored = typeof row.marks_scored === 'number' ? row.marks_scored : null;
          const totalMarks = typeof row.total_marks === 'number' ? row.total_marks : null;
          const resultSuffix = marksScored !== null && totalMarks !== null ? ` (${marksScored}/${totalMarks})` : '';

          let examColor = '#ef4444';
          if (marksScored !== null && totalMarks !== null && totalMarks > 0) {
            const pct = marksScored / totalMarks;
            if (pct >= 0.8) {
              examColor = '#10b981';
            } else if (pct >= 0.5) {
              examColor = '#f59e0b';
            } else {
              examColor = '#ef4444';
            }
          }

          return {
            id: `exam_${d.id}`,
            familyId,
            childId,
            parentId: familyId,
            title: `${String(row.subject || 'Exam')} Exam${resultSuffix}`,
            category: 'exam',
            color: examColor,
            startAt,
            endAt,
            allDay: false,
            timezone: 'Asia/Kolkata',
            recurrence: {
              type: ((row.recurrence_type || 'none') as any),
              interval: 1,
              byWeekDays: (Array.isArray(row.recurrence_days) ? row.recurrence_days : []),
              byMonthDays: [],
              until: null,
              count: null,
              rrule: null
            },
            taskStatus: (row.status as string) || 'scheduled',
            marksScored: marksScored,
            totalMarks: totalMarks,
            syllabusScope: (row.syllabus_scope as string) || '',
            linkedProgramId: (row.linked_program_id as string) || null,
            subjectId: (row.subject_id as string) || null,
            subject: (row.subject as string) || null,
            linkedTaskIds: [],
            participantIds: [],
            reminderIds: [],
            source: 'manual',
            sync: { googleEnabled: false, googleEventId: null, syncStatus: 'not_configured', lastSyncAt: null, syncError: null },
            createdBy: 'parent',
            createdAt: now,
            updatedAt: now,
            deletedAt: null
          };
        });
        setExamEvents(mappedExams);
      },
      (err) => {
        console.warn('Real-time exams stream failed:', err);
      }
    );

    return () => {
      unsubEvents();
      unsubTasks();
      unsubExams();
    };
  }, [childId, familyId, effectiveRange, useMockFallback]);

  const allEvents = useMemo(() => [...events, ...taskEvents, ...examEvents], [events, taskEvents, examEvents]);

  const upcoming = useMemo(
    () => allEvents.filter((event) => new Date(event.endAt).getTime() >= Date.now()).sort((a, b) => new Date(a.startAt).getTime() - new Date(b.startAt).getTime()),
    [allEvents]
  );

  return { events: allEvents, upcoming, loading, refresh: () => {} };
}

import { createContext, useCallback, useContext, useMemo, useState } from 'react';
import type { ReactNode } from 'react';

export type PlannerToastType = 'success' | 'error' | 'retry' | 'offline';

interface PlannerToast {
  id: string;
  type: PlannerToastType;
  message: string;
  actionLabel?: string;
  onAction?: () => void;
}

interface PlannerToastContextValue {
  toasts: PlannerToast[];
  pushToast: (toast: Omit<PlannerToast, 'id'>) => void;
  dismissToast: (id: string) => void;
}

const PlannerToastContext = createContext<PlannerToastContextValue | null>(null);

export function PlannerToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<PlannerToast[]>([]);

  const dismissToast = useCallback((id: string) => {
    setToasts((prev) => prev.filter((toast) => toast.id !== id));
  }, []);

  const pushToast = useCallback((toast: Omit<PlannerToast, 'id'>) => {
    const id = `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
    setToasts((prev) => [...prev, { ...toast, id }]);
    setTimeout(() => {
      setToasts((prev) => prev.filter((item) => item.id !== id));
    }, toast.type === 'error' ? 5500 : 3800);
  }, []);

  const value = useMemo(() => ({ toasts, pushToast, dismissToast }), [dismissToast, pushToast, toasts]);

  return (
    <PlannerToastContext.Provider value={value}>
      {children}
    </PlannerToastContext.Provider>
  );
}

export function usePlannerToast() {
  const ctx = useContext(PlannerToastContext);
  if (!ctx) throw new Error('usePlannerToast must be used within PlannerToastProvider');
  return ctx;
}

