import { useState, useEffect } from 'react';
import { collection, query, where, onSnapshot, addDoc, updateDoc, doc, getDocs, orderBy, getDoc } from 'firebase/firestore';
import { db } from '../config/firebase';
import type { Approval, Settlement } from '../types/schema';
import { createRewardLedgerEntry } from './useRewardLedger';
import { awardScratchRewardForTrigger } from './useScratchRewards';

export function useApprovals(familyId: string, childId?: string) {
  const [approvals, setApprovals] = useState<Approval[]>([]);
  const [settlements, setSettlements] = useState<Settlement[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Fetch approvals
  useEffect(() => {
    if (!familyId) return;

    let q = query(
      collection(db, 'approvals'),
      where('family_id', '==', familyId)
    );

    if (childId) {
      q = query(q, where('child_id', '==', childId));
    }

    const unsub = onSnapshot(
      q,
      (snap) => {
        const results = snap.docs.map(d => ({ id: d.id, ...d.data() } as Approval));
        // Client-side sort by created_at desc to avoid needing complex composite index if not present immediately
        results.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
        setApprovals(results);
        setLoading(false);
      },
      (err) => {
        console.error('Error fetching approvals:', err);
        setError(err.message);
        setLoading(false);
      }
    );
    return () => unsub();
  }, [familyId, childId]);

  // Fetch settlements
  useEffect(() => {
    if (!familyId) return;

    let q = query(
      collection(db, 'settlements'),
      where('family_id', '==', familyId)
    );

    if (childId) {
      q = query(q, where('child_id', '==', childId));
    }

    const unsub = onSnapshot(
      q,
      (snap) => {
        const results = snap.docs.map(d => ({ id: d.id, ...d.data() } as Settlement));
        results.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
        setSettlements(results);
      },
      (err) => {
        console.error('Error fetching settlements:', err);
      }
    );
    return () => unsub();
  }, [familyId, childId]);

  const requestApproval = async (approval: Omit<Approval, 'id' | 'created_at' | 'status'>) => {
    try {
      const now = new Date().toISOString();
      const docRef = await addDoc(collection(db, 'approvals'), {
        ...approval,
        status: 'pending',
        created_at: now,
      });
      return docRef.id;
    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  const resolveApproval = async (
    approvalId: string,
    status: 'approved' | 'rejected',
    parentId: string,
    options: { notifyChild?: boolean; awardPoints?: boolean } = {}
  ) => {
    try {
      const { notifyChild = true, awardPoints = true } = options;
      const ref = doc(db, 'approvals', approvalId);
      const snap = await getDoc(ref);
      if (!snap.exists()) throw new Error('Approval not found');

      const data = snap.data() as Approval;

      await updateDoc(ref, {
        status,
        reviewed_at: new Date().toISOString(),
        reviewed_by: parentId,
      });

      if (data.reference_id && ['task', 'exam'].includes(data.type)) {
        const targetCollection = data.type === 'task' ? 'tasks' : 'exams';
        await updateDoc(doc(db, targetCollection, data.reference_id), {
          approval_status: status,
          reviewed_at: new Date().toISOString(),
          reviewed_by: parentId,
        });
      }

      // If approved and has points, award to child
      if (awardPoints && status === 'approved' && data.points && data.points > 0) {
        const profileRef = doc(db, 'child_profile', data.child_id);
        const profileSnap = await getDoc(profileRef);
        if (profileSnap.exists()) {
          const profile = profileSnap.data();
          const currentStars = profile.total_stars || 0;
          await updateDoc(profileRef, {
            total_stars: currentStars + data.points
          });
          await createRewardLedgerEntry({
            child_id: data.child_id,
            parent_id: parentId,
            family_id: data.family_id,
            type: data.type === 'routine' ? 'bonus' : 'task_completed',
            stars_delta: data.points,
            title: data.title,
            reason: `${data.type === 'routine' ? 'Routine' : 'Task'} approved by parent: ${data.title}`,
            source_id: data.reference_id || approvalId,
            source_type: data.type === 'routine' ? 'routine' : 'approval',
            visible_to_child: true,
          });
          await awardScratchRewardForTrigger({
            childId: data.child_id,
            parentId,
            familyId: data.family_id,
            sourceId: data.reference_id || approvalId,
            sourceType: data.type === 'routine' ? 'routine' : 'approval',
            reason: `${data.type === 'routine' ? 'Routine' : 'Task'} approved: ${data.title}`,
          });
        }
      }

      // Send notification message to the child's inbox
      if (notifyChild) {
        await addDoc(collection(db, 'messages'), {
          child_id: data.child_id,
          parent_id: parentId,
          content: `Your ${data.type} request "${data.title}" was ${status}!`,
          timestamp: new Date().toISOString(),
          is_read: false,
          sender_role: 'parent',
          sender_id: parentId,
          subject: `Quest Resolution`
        });
      }

    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  const createSettlement = async (settlement: Omit<Settlement, 'id' | 'created_at' | 'status'>) => {
    try {
      const now = new Date().toISOString();
      const docRef = await addDoc(collection(db, 'settlements'), {
        ...settlement,
        status: 'draft',
        created_at: now,
      });
      return docRef.id;
    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  const markSettlementPaid = async (settlementId: string) => {
    try {
      const ref = doc(db, 'settlements', settlementId);
      await updateDoc(ref, {
        status: 'paid',
        paid_at: new Date().toISOString(),
      });
    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  return {
    approvals,
    settlements,
    loading,
    error,
    requestApproval,
    resolveApproval,
    createSettlement,
    markSettlementPaid
  };
}

import { useState, useEffect, useCallback } from 'react';
import { collection, query, where, onSnapshot, addDoc, updateDoc, doc, deleteDoc } from 'firebase/firestore';
import { db } from '../config/firebase';
import type { Challenge } from '../types/schema';

/**
 * Real-time CRUD hook for the parent-vs-child challenge system.
 * Challenges are mini-competitions (e.g., "Who reads 5 books first?") with a target score.
 * Both parent and child can increment their own score; once either hits the target, the challenge completes.
 */
export function useChallenges(parentId: string) {
  const [challenges, setChallenges] = useState<Challenge[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!parentId) {
      setChallenges([]);
      setLoading(false);
      return;
    }

    const q = query(collection(db, 'challenges'), where('parent_id', '==', parentId));

    const unsubscribe = onSnapshot(
      q,
      (snap) => {
        const mapped = snap.docs
          .map((d) => ({ id: d.id, ...(d.data() as Omit<Challenge, 'id'>) }))
          .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
        setChallenges(mapped);
        setLoading(false);
      },
      (error) => {
        console.warn('useChallenges failed:', error);
        setChallenges([]);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, [parentId]);

  const createChallenge = useCallback(async (
    title: string,
    childId: string,
    targetScore: number,
    description?: string,
    linkedProgramId?: string | null
  ) => {
    await addDoc(collection(db, 'challenges'), {
      title,
      description: description || '',
      parent_id: parentId,
      child_id: childId,
      parent_score: 0,
      child_score: 0,
      target_score: targetScore,
      status: 'active',
      linked_program_id: linkedProgramId || null,
      created_at: new Date().toISOString()
    });
  }, [parentId]);

  const incrementScore = useCallback(async (challengeId: string, who: 'parent' | 'child') => {
    const challenge = challenges.find(c => c.id === challengeId);
    if (!challenge || challenge.status === 'completed') return;

    const field = who === 'parent' ? 'parent_score' : 'child_score';
    const newScore = (who === 'parent' ? challenge.parent_score : challenge.child_score) + 1;
    const otherScore = who === 'parent' ? challenge.child_score : challenge.parent_score;

    const updates: Record<string, any> = { [field]: newScore };

    // Check if challenge is now complete
    if (newScore >= challenge.target_score) {
      updates.status = 'completed';
      updates.completed_at = new Date().toISOString();
      updates.winner = who;
    } else if (otherScore >= challenge.target_score) {
      updates.status = 'completed';
      updates.completed_at = new Date().toISOString();
      updates.winner = who === 'parent' ? 'child' : 'parent';
    }

    await updateDoc(doc(db, 'challenges', challengeId), updates);
  }, [challenges]);

  const deleteChallenge = useCallback(async (challengeId: string) => {
    await deleteDoc(doc(db, 'challenges', challengeId));
  }, []);

  const activeChallenges = challenges.filter(c => c.status === 'active');
  const completedChallenges = challenges.filter(c => c.status === 'completed');

  return {
    challenges,
    activeChallenges,
    completedChallenges,
    loading,
    createChallenge,
    incrementScore,
    deleteChallenge
  };
}

