export interface ChildProofItem extends ProofLog {
  child_id?: string;
  task_title?: string;
}

export function useChildProofs(childId: string) {
  const [proofs, setProofs] = useState<ChildProofItem[]>([]);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [pendingRetry, setPendingRetry] = useState<{ task: Task; file: File } | null>(null);

  useEffect(() => {
    if (!childId) {
      setProofs([]);
      return;
    }

    const unsubscribe = onSnapshot(
      query(collection(db, 'proof_logs'), where('child_id', '==', childId), limit(20)),
      (snapshot) => {
        const mapped = snapshot.docs
          .map((d) => ({ id: d.id, ...(d.data() as Omit<ChildProofItem, 'id'>) }))
          .sort((a, b) => b.timestamp.localeCompare(a.timestamp));
        setProofs(mapped);
      },
      (error) => {
        console.warn('useChildProofs fallback mode:', error);
        setProofs([]);
      }
    );

    return () => unsubscribe();
  }, [childId]);

  const uploadProof = useCallback(async (task: Task, file: File, notes?: string) => {
    if (!childId) throw new Error('Missing child id');

    setUploading(true);
    setUploadProgress(0);
    setPendingRetry(null);
    try {
      const optimizedBlob = await optimizeImage(file);
      const fileRef = ref(storage, `proofs/${childId}/${task.id}/${Date.now()}-${file.name.replace(/\.[^/.]+$/, "")}.jpg`);
      const uploadTask = uploadBytesResumable(fileRef, optimizedBlob);

      await new Promise<void>((resolve, reject) => {
        uploadTask.on(
          'state_changed',
          (snapshot) => {
            const progress = snapshot.totalBytes > 0
              ? Math.round((snapshot.bytesTransferred / snapshot.totalBytes) * 100)
              : 0;
            setUploadProgress(progress);
          },
          (error) => reject(error),
          () => resolve()
        );
      });

      const imageUrl = await getDownloadURL(fileRef);

      const proofDoc = await addDoc(collection(db, 'proof_logs'), {
        task_id: task.id,
        child_id: childId,
        task_title: task.title,
        image_url: imageUrl,
        image_path: fileRef.fullPath,
        timestamp: new Date().toISOString(),
        approval_status: 'pending',
        notes: notes || ''
      });

      // Create a unified approval request for the parent
      await addDoc(collection(db, 'approvals'), {
        family_id: task.family_id || '',
        child_id: childId,
        type: 'task',
        reference_id: task.id,
        title: task.title,
        points: Number(task.star_value || 0),
        status: 'pending',
        created_at: new Date().toISOString(),
        proof_image_url: imageUrl
      });

      return proofDoc.id;
    } catch (error) {
      setPendingRetry({ task, file });
      throw error;
    } finally {
      setUploading(false);
      setTimeout(() => setUploadProgress(0), 800);
    }
  }, [childId]);

  const retryUpload = useCallback(async () => {
    if (!pendingRetry) return null;
    return uploadProof(pendingRetry.task, pendingRetry.file);
  }, [pendingRetry, uploadProof]);

  return { proofs, uploading, uploadProgress, uploadProof, retryUpload, hasPendingRetry: Boolean(pendingRetry) };
}

export function useQuestActions(childId: string) {
  const [saving, setSaving] = useState(false);

  const markTaskPendingProof = useCallback(async (task: Task) => {
    if (!childId) return;
    const today = getTodayKey();
    const logId = `${childId}_${task.id}_${today}`;
    await setDoc(doc(db, 'task_logs', logId), {
      id: logId,
      child_id: childId,
      task_id: task.id,
      date: today,
      status: 'pending'
    }, { merge: true });
  }, [childId]);

  const completeTask = useCallback(async (task: Task) => {
    if (!childId) return;
    if ((task as any).created_by === 'child' && (task as any).approval_status !== 'approved') {
      throw new Error('This self-created task needs parent approval before completion rewards can be counted.');
    }

    const today = getTodayKey();
    const logId = `${childId}_${task.id}_${today}`;
    setSaving(true);
    try {
      await setDoc(doc(db, 'task_logs', logId), {
        id: logId,
        child_id: childId,
        task_id: task.id,
        date: today,
        status: 'completed'
      }, { merge: true });

      try {
        await updateDoc(doc(db, 'tasks', task.id), {
          status: 'completed',
          completed_at: new Date().toISOString()
        });
      } catch (error) {
        console.warn('Task status update skipped:', error);
      }

      const profileRef = doc(db, 'child_profile', childId);
      const snap = await getDoc(profileRef);
      if (snap.exists()) {
        const data = snap.data() as ChildProfile;

        // Gamification: Early Bird (completed before 8:30 AM)
        const currentHour = new Date().getHours();
        const currentMins = new Date().getMinutes();
        const isEarlyBird = data.last_task_date !== today && (currentHour < 8 || (currentHour === 8 && currentMins <= 30));

        const { updatedProfile } = applyTaskCompletionToProfile(data, task.star_value, true, today, isEarlyBird);
        const earnedStars = Math.max(0, Number(updatedProfile.total_stars || 0) - Number(data.total_stars || 0));
        const badgeText = `${task.title || ''} ${task.description || ''} ${task.category || ''}`.toLowerCase();
        const isReadingTask = /\b(read|reading|book|comic)\b/.test(badgeText);
        const isStudyTask = /\b(study|homework|math|science|english|practice|exam)\b/.test(badgeText);
        await updateDoc(profileRef, {
          total_stars: updatedProfile.total_stars,
          streak_count: updatedProfile.streak_count,
          streak_shields: updatedProfile.streak_shields,
          consistency_score: updatedProfile.consistency_score,
          last_task_date: updatedProfile.last_task_date,
          early_bird_count: (Number(data.early_bird_count) || 0) + (isEarlyBird ? 1 : 0),
          reading_completed_count: (Number(data.reading_completed_count) || 0) + (isReadingTask ? 1 : 0),
          study_completed_count: (Number(data.study_completed_count) || 0) + (isStudyTask ? 1 : 0)
        });

        if (earnedStars > 0) {
          await createRewardLedgerEntry({
            child_id: childId,
            parent_id: task.parent_id || task.family_id || data.parent_id || data.family_id || '',
            family_id: task.family_id || data.family_id || task.parent_id || data.parent_id || '',
            type: 'task_completed',
            stars_delta: earnedStars,
            title: task.title || 'Task completed',
            reason: isEarlyBird
              ? `Completed task "${task.title || 'Task'}" with early bird bonus`
              : `Completed task "${task.title || 'Task'}"`,
            source_id: task.id,
            source_type: 'task',
            visible_to_child: true,
          });
          await awardScratchRewardForTrigger({
            childId,
            parentId: task.parent_id || task.family_id || data.parent_id || data.family_id || '',
            familyId: task.family_id || data.family_id || task.parent_id || data.parent_id || '',
            sourceId: task.id,
            sourceType: 'task',
            reason: `Completed task "${task.title || 'Task'}"`,
          });
        }
      }
    } finally {
      setSaving(false);
    }
  }, [childId]);

  return { completeTask, markTaskPendingProof, saving };
}

