export const useRewards = (parentId: string) => {
  const [rewards, setRewards] = useState<RewardItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchRewards = async () => {
      try {
        setLoading(true);
        const rewardsRef = collection(db, 'reward_items');
        const [familySnapshot, parentSnapshot] = await Promise.all([
          getDocs(query(rewardsRef, where('family_id', '==', parentId), where('is_available', '==', true))),
          getDocs(query(rewardsRef, where('parent_id', '==', parentId), where('is_available', '==', true))),
        ]);

        const byFamily = familySnapshot.docs.map(doc => ({ id: doc.id, ...(doc.data() as Omit<RewardItem, 'id'>) }));
        const byParent = parentSnapshot.docs.map(doc => ({ id: doc.id, ...(doc.data() as Omit<RewardItem, 'id'>) }));
        setRewards(mergeRewards([byFamily, byParent]));
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to fetch rewards');
      } finally {
        setLoading(false);
      }
    };

    if (parentId) {
      fetchRewards();
    }
  }, [parentId]);

  const createReward = async (newReward: Omit<RewardItem, 'id' | 'created_at' | 'updated_at'>) => {
    try {
      const rewardsRef = collection(db, 'reward_items');
      const now = new Date().toISOString();

      const docRef = await addDoc(rewardsRef, {
        ...newReward,
        created_at: now,
        updated_at: now,
      });

      const created: RewardItem = {
        ...newReward,
        id: docRef.id,
        created_at: now,
        updated_at: now,
      };

      setRewards([...rewards, created].sort((a, b) => a.star_cost - b.star_cost));
      return created;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to create reward');
      throw err;
    }
  };

  const updateReward = async (id: string, updates: Partial<Omit<RewardItem, 'id' | 'created_at'>>) => {
    try {
      const rewardsRef = doc(db, 'reward_items', id);
      const now = new Date().toISOString();

      await updateDoc(rewardsRef, {
        ...updates,
        updated_at: now,
      });

      setRewards(
        rewards.map(r =>
          r.id === id
            ? {
                ...r,
                ...updates,
                updated_at: now,
              }
            : r
        )
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to update reward');
      throw err;
    }
  };

  const deleteReward = async (id: string) => {
    try {
      await deleteDoc(doc(db, 'reward_items', id));
      setRewards(rewards.filter(r => r.id !== id));
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete reward');
      throw err;
    }
  };

  return {
    rewards,
    loading,
    error,
    createReward,
    updateReward,
    deleteReward,
  };
};

export const useRedemptions = (childId: string, parentId: string) => {
  const [redemptions, setRedemptions] = useState<Redemption[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchRedemptions = async () => {
      try {
        setLoading(true);
        const redemptionsRef = collection(db, 'redemptions');
        const q = query(
          redemptionsRef,
          where('child_id', '==', childId),
          where('parent_id', '==', parentId)
        );

        const snapshot = await getDocs(q);
        const fetchedRedemptions = snapshot.docs.map(doc => ({ id: doc.id, ...(doc.data() as Omit<Redemption, 'id'>) }));
        setRedemptions(fetchedRedemptions);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to fetch redemptions');
      } finally {
        setLoading(false);
      }
    };

    if (childId && parentId) {
      fetchRedemptions();
    }
  }, [childId, parentId]);

  const requestRedemption = async (
    rewardItemId: string,
    rewardItem: RewardItem,
    currentStars: number
  ): Promise<Redemption> => {
    if (currentStars < rewardItem.star_cost) {
      throw new Error('Not enough stars for this reward');
    }

    try {
      const redemptionsRef = collection(db, 'redemptions');
      const now = new Date().toISOString();

      const docRef = await addDoc(redemptionsRef, {
        child_id: childId,
        parent_id: parentId,
        reward_item_id: rewardItemId,
        reward_item: rewardItem,
        stars_spent: rewardItem.star_cost,
        status: 'pending',
        requested_at: now,
      });

      const newRedemption: Redemption = {
        id: docRef.id,
        child_id: childId,
        parent_id: parentId,
        reward_item_id: rewardItemId,
        reward_item: rewardItem,
        stars_spent: rewardItem.star_cost,
        status: 'pending',
        requested_at: now,
      };

      setRedemptions([...redemptions, newRedemption]);
      return newRedemption;
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to request redemption');
      throw err;
    }
  };

  const updateRedemptionStatus = async (
    id: string,
    status: 'approved' | 'completed' | 'rejected',
    notes?: string
  ) => {
    try {
      const redemptionsRef = doc(db, 'redemptions', id);
      const updates: any = {
        status,
        updated_at: new Date().toISOString(),
      };

      if (status === 'completed') {
        updates.completed_at = new Date().toISOString();
      }

      const existingRedemption = redemptions.find(r => r.id === id);
      if (status === 'approved' && existingRedemption && existingRedemption.status === 'pending') {
        const profileRef = doc(db, 'child_profile', existingRedemption.child_id);
        const profileSnap = await getDoc(profileRef);
        if (profileSnap.exists()) {
          const totalStars = Number(profileSnap.data().total_stars) || 0;
          await updateDoc(profileRef, {
            total_stars: Math.max(0, totalStars - existingRedemption.stars_spent),
          });
          await createRewardLedgerEntry({
            child_id: existingRedemption.child_id,
            parent_id: existingRedemption.parent_id,
            family_id: existingRedemption.reward_item.family_id || existingRedemption.parent_id,
            type: 'redemption',
            stars_delta: -Math.abs(existingRedemption.stars_spent),
            title: existingRedemption.reward_item.name,
            reason: `Redeemed stars for ${existingRedemption.reward_item.name}`,
            source_id: existingRedemption.id,
            source_type: 'redemption',
            visible_to_child: true,
          });
        }
      }

      if (status === 'rejected' && existingRedemption && ['approved', 'completed'].includes(existingRedemption.status)) {
        const profileRef = doc(db, 'child_profile', existingRedemption.child_id);
        const profileSnap = await getDoc(profileRef);
        if (profileSnap.exists()) {
          const totalStars = Number(profileSnap.data().total_stars) || 0;
          await updateDoc(profileRef, {
            total_stars: totalStars + existingRedemption.stars_spent,
          });
          await createRewardLedgerEntry({
            child_id: existingRedemption.child_id,
            parent_id: existingRedemption.parent_id,
            family_id: existingRedemption.reward_item.family_id || existingRedemption.parent_id,
            type: 'adjustment',
            stars_delta: Math.abs(existingRedemption.stars_spent),
            title: `${existingRedemption.reward_item.name} refunded`,
            reason: `Stars returned after reward request was rejected`,
            source_id: existingRedemption.id,
            source_type: 'redemption',
            visible_to_child: true,
          });
        }
      }

      if (notes) {
        updates.notes = notes;
      }

      await updateDoc(redemptionsRef, updates);

      setRedemptions(
        redemptions.map(r =>
          r.id === id
            ? {
                ...r,
                status,
                completed_at: status === 'completed' ? new Date().toISOString() : r.completed_at,
                notes: notes || r.notes,
              }
            : r
        )
      );
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to update redemption');
      throw err;
    }
  };

  return {
    redemptions,
    loading,
    error,
    requestRedemption,
    updateRedemptionStatus,
  };
};

import { useState, useEffect } from 'react';
import {
  collection, query, where, onSnapshot, addDoc,
  updateDoc, doc, getDocs, orderBy, limit, setDoc, getDoc
} from 'firebase/firestore';
import { db } from '../config/firebase';
import type { Routine, RoutineLog } from '../types/schema';
import { useSickMode } from './useSickMode';
import { createRewardLedgerEntry } from './useRewardLedger';

export interface RoutineLogResult {
  status: 'completed' | 'missed' | 'sick';
  inTimeWindow: boolean;
  starsAwarded: number;
  starsDelta: number;
  requiresApproval: boolean;
  alreadyLogged?: boolean;
}

/** Returns the effective day range key for today */
export function getTodayDayRange(): 'weekday' | 'weekend' {
  const day = new Date().getDay(); // 0=Sun, 6=Sat
  return (day === 0 || day === 6) ? 'weekend' : 'weekday';
}

function getTodayKey() {
  const today = new Date();
  return (
    today.getFullYear() +
    '-' + String(today.getMonth() + 1).padStart(2, '0') +
    '-' + String(today.getDate()).padStart(2, '0')
  );
}

async function runRoutineSideEffect(label: string, work: () => Promise<void>) {
  try {
    await work();
  } catch (error) {
    console.warn(`${label} skipped:`, error);
  }
}

function timeToMinutes(value: string | undefined | null) {
  if (!value) return null;
  const [hoursRaw, minutesRaw] = value.split(':');
  const hours = Number(hoursRaw);
  const minutes = Number(minutesRaw);
  if (!Number.isFinite(hours) || !Number.isFinite(minutes)) return null;
  return hours * 60 + minutes;
}

function isTimeInRange(actualTime: string | undefined, startTime: string, endTime: string) {
  const actual = timeToMinutes(actualTime);
  const start = timeToMinutes(startTime);
  const end = timeToMinutes(endTime);
  if (actual == null || start == null || end == null) return false;
  if (start <= end) return actual >= start && actual <= end;
  return actual >= start || actual <= end;
}

async function applyStarsDelta(childId: string, familyId: string, routine: Routine, starsDelta: number, reason: string) {
  if (!starsDelta) return;
  const profileRef = doc(db, 'child_profile', childId);
  const profileSnap = await getDoc(profileRef);
  const profile = profileSnap.exists() ? profileSnap.data() : null;
  const currentStars = Number(profile?.total_stars || 0);
  await updateDoc(profileRef, {
    total_stars: Math.max(0, currentStars + starsDelta)
  });
  await createRewardLedgerEntry({
    child_id: childId,
    parent_id: familyId,
    family_id: familyId,
    type: starsDelta > 0 ? 'bonus' : 'adjustment',
    stars_delta: starsDelta,
    title: routine.title,
    reason,
    source_id: routine.id,
    source_type: 'routine',
    visible_to_child: true,
  });
}

export function useRoutines(familyId: string, childId?: string) {
  const [routines, setRoutines] = useState<Routine[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const { getActiveSickPeriod } = useSickMode(familyId, childId || '');

  useEffect(() => {
    if (!familyId) {
      setRoutines([]);
      setLoading(false);
      return;
    }

    // Query by family_id only to avoid composite index requirements;
    // filter child_id client-side to handle null/''/childId cases.
    const q = query(
      collection(db, 'routines'),
      where('family_id', '==', familyId),
      where('status', '==', 'active')
    );

    const unsubscribe = onSnapshot(
      q,
      (snapshot) => {
        let results = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as Routine));

        // Client-side filter: include routines assigned to this child OR to all children
        if (childId) {
          results = results.filter(r => !r.child_id || r.child_id === '' || r.child_id === childId);
        }

        // Normalize: support old schedule_time field on existing docs
        results = results.map(r => ({
          ...r,
          start_time: r.start_time || r.schedule_time || '07:00',
          end_time: r.end_time || r.schedule_time || '08:00',
          day_range: r.day_range || 'everyday',
          requires_approval: r.requires_approval ?? false,
          created_by: r.created_by || 'parent',
        }));

        // Sort by start_time ascending
        results.sort((a, b) => a.start_time.localeCompare(b.start_time));
        setRoutines(results);
        setLoading(false);
      },
      (err) => {
        console.error('Error fetching routines:', err);
        setError(err.message);
        setLoading(false);
      }
    );

    return () => unsubscribe();
  }, [familyId, childId]);

  const createRoutine = async (
    routine: Omit<Routine, 'id' | 'created_at' | 'updated_at' | 'streak'>
  ) => {
    try {
      const now = new Date().toISOString();
      const payload = {
        ...routine,
        // keep backward-compat field
        schedule_time: routine.start_time,
        streak: 0,
        created_at: now,
        updated_at: now,
      };
      const docRef = await addDoc(collection(db, 'routines'), payload);
      return docRef.id;
    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  const updateRoutine = async (id: string, updates: Partial<Routine>) => {
    try {
      const ref = doc(db, 'routines', id);
      const payload: any = { ...updates, updated_at: new Date().toISOString() };
      if (updates.start_time) payload.schedule_time = updates.start_time;
      await updateDoc(ref, payload);
    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  const archiveRoutine = async (id: string) => {
    return updateRoutine(id, { status: 'archived' });
  };

  const logRoutine = async (
    routine: Routine,
    targetChildId: string,
    status: 'completed' | 'missed' | 'sick',
    actualCompletedTime?: string
  ): Promise<RoutineLogResult> => {
    try {
      const today = new Date();
      const dateStr = getTodayKey();

      // Sick mode override
      const sickPeriod = getActiveSickPeriod(targetChildId);
      if (sickPeriod) status = 'sick';

      const logId = `${targetChildId}_${routine.id}_${dateStr}`;
      const logRef = doc(db, 'routine_logs', logId);
      const existingLogSnap = await getDoc(logRef);
      if (existingLogSnap.exists()) {
        const existingLog = existingLogSnap.data() as RoutineLog;
        if (existingLog.status === status || existingLog.status === 'completed' || existingLog.status === 'sick') {
          return {
            status: existingLog.status,
            inTimeWindow: existingLog.in_time_window ?? true,
            starsAwarded: Number(existingLog.stars_awarded || 0),
            starsDelta: Number(existingLog.stars_delta || 0),
            requiresApproval: routine.requires_approval,
            alreadyLogged: true
          };
        }
      }

      const routineStart = routine.start_time || routine.schedule_time || '00:00';
      const routineEnd = routine.end_time || routine.schedule_time || routineStart;
      const inTimeWindow = status === 'completed' ? isTimeInRange(actualCompletedTime, routineStart, routineEnd) : false;
      const starsAwarded = status === 'completed' && inTimeWindow ? Number(routine.points || 0) : 0;
      const starsDelta = status === 'missed' ? -Math.abs(Number(routine.points || 0)) : (routine.requires_approval ? 0 : starsAwarded);

      const logData: RoutineLog = {
        id: logId,
        routine_id: routine.id,
        family_id: familyId,
        child_id: targetChildId,
        date: dateStr,
        status,
        completed_at: status === 'completed' ? new Date().toISOString() : undefined,
        actual_completed_time: status === 'completed' ? actualCompletedTime : undefined,
        in_time_window: status === 'completed' ? inTimeWindow : undefined,
        stars_awarded: starsAwarded,
        stars_delta: starsDelta,
      };

      await setDoc(logRef, logData, { merge: true });

      if (status === 'missed' && starsDelta < 0) {
        await runRoutineSideEffect('Routine missed penalty', async () => {
          await applyStarsDelta(targetChildId, familyId, routine, starsDelta, `Missed routine after daily lockout: ${routine.title}`);
        });
      }

      if (status === 'completed') {
        // If approval required, create pending approval; otherwise grant stars directly
        if (routine.requires_approval && starsAwarded > 0) {
          await runRoutineSideEffect('Routine approval creation', async () => {
            const pendingApprovalsQuery = query(
              collection(db, 'approvals'),
              where('family_id', '==', familyId),
              where('child_id', '==', targetChildId),
              where('type', '==', 'routine'),
              where('reference_id', '==', routine.id),
              where('status', '==', 'pending')
            );
            const pendingApprovalsSnapshot = await getDocs(pendingApprovalsQuery);
            const hasPendingApprovalToday = pendingApprovalsSnapshot.docs.some((approvalDoc) => {
              const approval = approvalDoc.data();
              const submittedDate = approval.created_at
                ? new Date(approval.created_at).toISOString().slice(0, 10)
                : '';

              return submittedDate === dateStr;
            });

            if (!hasPendingApprovalToday) {
              await addDoc(collection(db, 'approvals'), {
                family_id: familyId,
                child_id: targetChildId,
                type: 'routine',
                reference_id: routine.id,
                title: routine.title,
                points: starsAwarded,
                status: 'pending',
                created_at: new Date().toISOString(),
              });
            }
          });
        } else if (!routine.requires_approval && starsAwarded > 0) {
          await runRoutineSideEffect('Routine star award', async () => {
            await applyStarsDelta(targetChildId, familyId, routine, starsAwarded, `Completed routine on time: ${routine.title}`);
          });
        }

        // Evaluate and update streak
        await runRoutineSideEffect('Routine streak update', async () => {
          const qLogs = query(
            collection(db, 'routine_logs'),
            where('routine_id', '==', routine.id),
            where('child_id', '==', targetChildId),
            where('status', '==', 'completed'),
            orderBy('date', 'desc'),
            limit(2)
          );
          const snapshot = await getDocs(qLogs);
          const completedLogs = snapshot.docs.map(d => d.data() as RoutineLog);

          let newStreak = routine.streak || 0;
          if (completedLogs.length > 1) {
            const previousDate = new Date(completedLogs[1].date);
            const diffDays = Math.floor(
              (today.getTime() - previousDate.getTime()) / (1000 * 3600 * 24)
            );
            newStreak = diffDays === 1 ? newStreak + 1 : 1;
          } else {
            newStreak = 1;
          }

          await updateRoutine(routine.id, { streak: newStreak });
        });
      }

      return {
        status,
        inTimeWindow,
        starsAwarded,
        starsDelta,
        requiresApproval: routine.requires_approval
      };
    } catch (err: any) {
      setError(err.message);
      throw err;
    }
  };

  const getTodayLogs = async (targetChildId: string) => {
    const today = new Date();
    const dateStr =
      today.getFullYear() +
      '-' + String(today.getMonth() + 1).padStart(2, '0') +
      '-' + String(today.getDate()).padStart(2, '0');

    const qLogs = query(
      collection(db, 'routine_logs'),
      where('family_id', '==', familyId),
      where('child_id', '==', targetChildId),
      where('date', '==', dateStr)
    );
    const snapshot = await getDocs(qLogs);
    return snapshot.docs.map(d => ({ id: d.id, ...d.data() } as RoutineLog));
  };

  return {
    routines,
    loading,
    error,
    createRoutine,
    updateRoutine,
    archiveRoutine,
    logRoutine,
    getTodayLogs,
  };
}

import { useState, useEffect, useCallback } from 'react';
import { db } from '../config/firebase';
import {
  collection,
  query,
  where,
  onSnapshot,
  addDoc,
  updateDoc,
  doc,
  orderBy,
} from 'firebase/firestore';

export interface SickPeriod {
  id: string;
  family_id: string;
  child_id: string;
  initiated_by: string;
  initiated_by_role: 'parent' | 'child';
  start_date: string; // YYYY-MM-DD
  end_date: string; // YYYY-MM-DD
  status: 'active' | 'pending_approval' | 'rejected' | 'ended';
  approved_by?: string;
  approved_at?: string;
  reason?: string;
  created_at: string;
  updated_at: string;
}

export function useSickMode(familyId: string, childId?: string) {
  const [sickPeriods, setSickPeriods] = useState<SickPeriod[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!familyId) return;

    let q = query(
      collection(db, 'sick_periods'),
      where('family_id', '==', familyId)
    );

    if (childId) {
      q = query(q, where('child_id', '==', childId));
    }

    const unsub = onSnapshot(q, (snap) => {
      const periods = snap.docs.map((d) => ({
        id: d.id,
        ...d.data(),
      })) as SickPeriod[];

      // Sort in memory since we might not have a composite index for start_date yet
      periods.sort((a, b) => b.start_date.localeCompare(a.start_date));
      setSickPeriods(periods);
      setLoading(false);
    });

    return () => unsub();
  }, [familyId, childId]);

  const initiateSickPeriod = useCallback(
    async (
      targetChildId: string,
      role: 'parent' | 'child',
      initiatorId: string,
      startDate: string,
      endDate: string,
      reason?: string
    ) => {
      const payload: Omit<SickPeriod, 'id'> = {
        family_id: familyId,
        child_id: targetChildId,
        initiated_by: initiatorId,
        initiated_by_role: role,
        start_date: startDate,
        end_date: endDate,
        status: role === 'parent' ? 'active' : 'pending_approval',
        reason,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      };

      if (role === 'parent') {
        payload.approved_by = initiatorId;
        payload.approved_at = payload.created_at;
      }

      await addDoc(collection(db, 'sick_periods'), payload);
    },
    [familyId]
  );

  const updateSickPeriodStatus = useCallback(
    async (id: string, status: SickPeriod['status'], approverId?: string) => {
      const payload: Partial<SickPeriod> = {
        status,
        updated_at: new Date().toISOString(),
      };

      if (status === 'active' && approverId) {
        payload.approved_by = approverId;
        payload.approved_at = new Date().toISOString();
      }

      await updateDoc(doc(db, 'sick_periods', id), payload);
    },
    []
  );

  const getActiveSickPeriod = useCallback((targetChildId: string) => {
    const today = new Date().toISOString().slice(0, 10);
    return sickPeriods.find(
      (p) =>
        p.child_id === targetChildId &&
        p.status === 'active' &&
        p.start_date <= today &&
        p.end_date >= today
    );
  }, [sickPeriods]);

  const isDateSick = useCallback((targetChildId: string, dateStr: string) => {
    return sickPeriods.some(
      (p) =>
        p.child_id === targetChildId &&
        p.status === 'active' &&
        p.start_date <= dateStr &&
        p.end_date >= dateStr
    );
  }, [sickPeriods]);

  const pendingRequests = sickPeriods.filter((p) => p.status === 'pending_approval');

  return {
    sickPeriods,
    pendingRequests,
    loading,
    initiateSickPeriod,
    updateSickPeriodStatus,
    getActiveSickPeriod,
    isDateSick,
  };
}

import { useEffect, useState, useCallback } from 'react';
import { db } from '../config/firebase';
import {
  collection,
  query,
  where,
  getDocs,
  addDoc,
  deleteDoc,
} from 'firebase/firestore';
import type { Task, RoutineConfiguration, ChildProfile, ExamResult, Event, MoodLog } from '../types/schema';
import {
  generateSmartDailyTasks,
  generateExamPrepTasks,
} from '../utils/taskScheduler';

interface ScheduledTask extends Task {
  generated_at: string;
  generation_reason: string;
  expires_at?: string;
  is_generated: boolean;
}

function stripUndefinedFields<T extends Record<string, unknown>>(input: T): Partial<T> {
  return Object.fromEntries(
    Object.entries(input).filter(([, value]) => value !== undefined)
  ) as Partial<T>;
}

export const useTaskScheduler = (
  childId: string,
  parentId: string,
  routine: RoutineConfiguration | null,
  profile: ChildProfile | null,
  exams: ExamResult[],
  events: Event[],
  currentMood?: MoodLog
) => {
  const [scheduledTasks, setScheduledTasks] = useState<ScheduledTask[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Calculate weekly completion rate
  const calculateWeeklyRate = useCallback(async (): Promise<number> => {
    try {
      const taskLogsRef = collection(db, 'task_logs');
      const weekAgo = new Date();
      weekAgo.setDate(weekAgo.getDate() - 7);
      const weekAgoStr = weekAgo.toISOString().split('T')[0];
      const todayStr = new Date().toISOString().split('T')[0];

      const q = query(
        taskLogsRef,
        where('child_id', '==', childId),
        where('date', '>=', weekAgoStr),
        where('date', '<=', todayStr)
      );

      const snapshot = await getDocs(q);
      const logs = snapshot.docs.map(doc => doc.data() as any);

      if (logs.length === 0) return 0;

      const completed = logs.filter(log => log.status === 'completed').length;
      return Math.round((completed / logs.length) * 100);
    } catch (err) {
      console.error('Error calculating weekly rate:', err);
      return 50;
    }
  }, [childId]);

  // Generate and save tasks for today
  const generateTodaysTasks = useCallback(async () => {
    if (!routine || !profile) {
      setError('Routine or profile not available');
      return;
    }

    try {
      setLoading(true);
      const weeklyRate = await calculateWeeklyRate();
      const routineSlots = routine.current_mode === 'academic'
        ? routine.school_days_routine
        : routine.vacation_routine;

      const generatedTasks = generateSmartDailyTasks(
        routineSlots,
        profile,
        exams,
        events,
        currentMood?.mood,
        weeklyRate
      );

      // Convert to ScheduledTask and save to Firestore
      const tasksRef = collection(db, 'tasks');
      const savedTasks: ScheduledTask[] = [];

      for (const generated of generatedTasks) {
        // Check if similar task already exists today
        const q = query(
          tasksRef,
          where('child_id', '==', childId),
          where('title', '==', generated.title)
        );
        const existing = await getDocs(q);

        if (existing.empty) {
          const nowIso = new Date().toISOString();
          const taskPayload = stripUndefinedFields({
            ...generated,
            child_id: childId,
            parent_id: parentId,
            is_generated: true,
            status: 'pending',
            created_at: nowIso,
          });
          const docRef = await addDoc(tasksRef, taskPayload);

          savedTasks.push({
            id: docRef.id,
            child_id: childId,
            parent_id: parentId,
            ...generated,
            is_generated: true,
            status: 'pending',
            created_at: nowIso,
          } as ScheduledTask);
        }
      }

      setScheduledTasks(savedTasks);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate tasks');
    } finally {
      setLoading(false);
    }
  }, [routine, profile, exams, events, currentMood, childId, parentId, calculateWeeklyRate]);

  // Generate exam prep tasks
  const generateExamTasks = useCallback(async (exam: Event, daysUntil: number) => {
    if (!profile) {
      setError('Profile not available');
      return;
    }

    try {
      setLoading(true);
      const generatedTasks = generateExamPrepTasks(exam, daysUntil, profile);

      const tasksRef = collection(db, 'tasks');
      const savedTasks: ScheduledTask[] = [];

      for (const generated of generatedTasks) {
        const nowIso = new Date().toISOString();
        const taskPayload = stripUndefinedFields({
          ...generated,
          child_id: childId,
          parent_id: parentId,
          is_generated: true,
          status: 'pending',
          created_at: nowIso,
        });
        const docRef = await addDoc(tasksRef, taskPayload);

        savedTasks.push({
          id: docRef.id,
          child_id: childId,
          parent_id: parentId,
          ...generated,
          is_generated: true,
          status: 'pending',
          created_at: nowIso,
        } as ScheduledTask);
      }

      setScheduledTasks(prev => [...prev, ...savedTasks]);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate exam tasks');
    } finally {
      setLoading(false);
    }
  }, [childId, parentId, profile]);

  // Clean up expired tasks
  const cleanupExpiredTasks = useCallback(async () => {
    try {
      const now = new Date().toISOString();
      const tasksRef = collection(db, 'tasks');
      const q = query(
        tasksRef,
        where('child_id', '==', childId),
        where('expires_at', '<', now),
        where('is_generated', '==', true)
      );

      const snapshot = await getDocs(q);
      for (const doc of snapshot.docs) {
        if ((doc.data() as Task).is_mandatory === true) continue;
        await deleteDoc(doc.ref);
      }

      setScheduledTasks(prev =>
        prev.filter(t => t.is_mandatory || !t.expires_at || new Date(t.expires_at) > new Date())
      );
    } catch (err) {
      console.error('Error cleaning up expired tasks:', err);
    }
  }, [childId]);

  // Fetch existing scheduled tasks
  useEffect(() => {
    const fetchTasks = async () => {
      try {
        const tasksRef = collection(db, 'tasks');
        const q = query(
          tasksRef,
          where('child_id', '==', childId),
          where('is_generated', '==', true)
        );

        const snapshot = await getDocs(q);
        const tasks = snapshot.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        } as ScheduledTask));

        setScheduledTasks(tasks);
      } catch (err) {
        console.error('Error fetching scheduled tasks:', err);
      }
    };

    if (childId) {
      fetchTasks();
      cleanupExpiredTasks();
    }
  }, [childId, cleanupExpiredTasks]);

  return {
    scheduledTasks,
    loading,
    error,
    generateTodaysTasks,
    generateExamTasks,
    cleanupExpiredTasks,
  };
};

import { useEffect, useRef, useState, useCallback } from 'react';

interface WebSocketMessage {
  type: string;
  payload: any;
  timestamp: number;
}

interface UseWebSocketOptions {
  url?: string;
  protocols?: string | string[];
  shouldReconnect?: boolean;
  reconnectInterval?: number;
  maxReconnectAttempts?: number;
  onOpen?: (event: Event) => void;
  onClose?: (event: CloseEvent) => void;
  onError?: (event: Event) => void;
  onMessage?: (message: WebSocketMessage) => void;
}

interface UseWebSocketReturn {
  socket: WebSocket | null;
  isConnected: boolean;
  connectionState: 'connecting' | 'connected' | 'disconnected' | 'error';
  lastMessage: WebSocketMessage | null;
  sendMessage: (type: string, payload: any) => void;
  reconnect: () => void;
  close: () => void;
  reconnectAttempts: number;
}

export const useWebSocket = (options: UseWebSocketOptions = {}): UseWebSocketReturn => {
  const {
    url = `wss://${process.env.REACT_APP_FIREBASE_PROJECT_ID}.firebaseapp.com/ws`,
    protocols,
    shouldReconnect = true,
    reconnectInterval = 3000,
    maxReconnectAttempts = 5,
    onOpen,
    onClose,
    onError,
    onMessage,
  } = options;

  const [socket, setSocket] = useState<WebSocket | null>(null);
  const [isConnected, setIsConnected] = useState(false);
  const [connectionState, setConnectionState] = useState<'connecting' | 'connected' | 'disconnected' | 'error'>('disconnected');
  const [lastMessage, setLastMessage] = useState<WebSocketMessage | null>(null);
  const [reconnectAttempts, setReconnectAttempts] = useState(0);

  const socketRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
  const shouldReconnectRef = useRef(shouldReconnect);

  // Create WebSocket connection
  const createConnection = useCallback(() => {
    try {
      setConnectionState('connecting');
      const ws = new WebSocket(url, protocols);
      socketRef.current = ws;
      setSocket(ws);

      ws.onopen = (event) => {
        console.log('WebSocket connected');
        setSocket(ws);
        setIsConnected(true);
        setConnectionState('connected');
        setReconnectAttempts(0);
        onOpen?.(event);
      };

      ws.onclose = (event) => {
        console.log('WebSocket disconnected:', event.code, event.reason);
        socketRef.current = null;
        setSocket(null);
        setIsConnected(false);
        setConnectionState('disconnected');
        onClose?.(event);

        // Attempt reconnection if enabled
        if (shouldReconnectRef.current && reconnectAttempts < maxReconnectAttempts) {
          reconnectTimeoutRef.current = setTimeout(() => {
            setReconnectAttempts(prev => prev + 1);
            createConnection();
          }, reconnectInterval);
        }
      };

      ws.onerror = (event) => {
        console.error('WebSocket error:', event);
        setConnectionState('error');
        onError?.(event);
      };

      ws.onmessage = (event) => {
        try {
          const message: WebSocketMessage = JSON.parse(event.data);
          setLastMessage(message);
          onMessage?.(message);
        } catch (error) {
          console.error('Failed to parse WebSocket message:', error);
        }
      };

      return ws;
    } catch (error) {
      console.error('Failed to create WebSocket connection:', error);
      setConnectionState('error');
      return null;
    }
  }, [url, protocols, reconnectAttempts, maxReconnectAttempts, reconnectInterval, onOpen, onClose, onError, onMessage]);

  // Send message
  const sendMessage = useCallback((type: string, payload: any) => {
    const currentSocket = socketRef.current || socket;
    const openState = typeof WebSocket.OPEN === 'number' ? WebSocket.OPEN : 1;
    if (currentSocket && currentSocket.readyState === openState) {
      const message: WebSocketMessage = {
        type,
        payload,
        timestamp: Date.now(),
      };
      currentSocket.send(JSON.stringify(message));
    } else {
      console.warn('WebSocket is not connected. Message not sent:', type, payload);
    }
  }, [socket]);

  // Manual reconnect
  const reconnect = useCallback(() => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }
    setReconnectAttempts(0);
    createConnection();
  }, [createConnection]);

  // Close connection
  const close = useCallback(() => {
    shouldReconnectRef.current = false;
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }
    const currentSocket = socketRef.current || socket;
    if (currentSocket) {
      currentSocket.close();
    }
  }, [socket]);

  // Initialize connection on mount
  useEffect(() => {
    const ws = createConnection();

    return () => {
      if (ws) {
        ws.close();
      }
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
    };
  }, [createConnection]);

  // Update shouldReconnect ref
  useEffect(() => {
    shouldReconnectRef.current = shouldReconnect;
  }, [shouldReconnect]);

  return {
    socket,
    isConnected,
    connectionState,
    lastMessage,
    sendMessage,
    reconnect,
    close,
    reconnectAttempts,
  };
};

// Hook for real-time collaboration features
export const useRealTimeCollaboration = (roomId: string, userId: string) => {
  const [participants, setParticipants] = useState<Set<string>>(new Set());
  const [isTyping, setIsTyping] = useState<Set<string>>(new Set());
  const [lastActivity, setLastActivity] = useState<Map<string, number>>(new Map());

  const { sendMessage, isConnected } = useWebSocket({
    onMessage: (message) => {
      switch (message.type) {
        case 'user_joined':
          setParticipants(prev => new Set([...prev, message.payload.userId]));
          setLastActivity(prev => new Map(prev.set(message.payload.userId, Date.now())));
          break;

        case 'user_left':
          setParticipants(prev => {
            const newSet = new Set(prev);
            newSet.delete(message.payload.userId);
            return newSet;
          });
          break;

        case 'typing_start':
          setIsTyping(prev => new Set([...prev, message.payload.userId]));
          break;

        case 'typing_stop':
          setIsTyping(prev => {
            const newSet = new Set(prev);
            newSet.delete(message.payload.userId);
            return newSet;
          });
          break;

        case 'activity':
          setLastActivity(prev => new Map(prev.set(message.payload.userId, Date.now())));
          break;
      }
    },
  });

  // Join room
  const joinRoom = useCallback(() => {
    sendMessage('join_room', { roomId, userId });
  }, [sendMessage, roomId, userId]);

  // Leave room
  const leaveRoom = useCallback(() => {
    sendMessage('leave_room', { roomId, userId });
  }, [sendMessage, roomId, userId]);

  // Send typing indicator
  const startTyping = useCallback(() => {
    sendMessage('typing_start', { roomId, userId });
  }, [sendMessage, roomId, userId]);

  const stopTyping = useCallback(() => {
    sendMessage('typing_stop', { roomId, userId });
  }, [sendMessage, roomId, userId]);

  // Send activity ping
  const pingActivity = useCallback(() => {
    sendMessage('activity', { roomId, userId });
  }, [sendMessage, roomId, userId]);

  // Auto-ping activity every 30 seconds
  useEffect(() => {
    if (!isConnected) return;

    const interval = setInterval(pingActivity, 30000);
    return () => clearInterval(interval);
  }, [isConnected, pingActivity]);

  return {
    participants,
    isTyping,
    lastActivity,
    joinRoom,
    leaveRoom,
    startTyping,
    stopTyping,
    isConnected,
  };
};

// Hook for real-time messaging
export const useRealTimeMessaging = (conversationId: string, userId: string) => {
  const [messages, setMessages] = useState<any[]>([]);
  const [onlineUsers, setOnlineUsers] = useState<Set<string>>(new Set());

  const { sendMessage, isConnected } = useWebSocket({
    onMessage: (message) => {
      switch (message.type) {
        case 'new_message':
          setMessages(prev => [...prev, message.payload]);
          break;

        case 'user_online':
          setOnlineUsers(prev => new Set([...prev, message.payload.userId]));
          break;

        case 'user_offline':
          setOnlineUsers(prev => {
            const newSet = new Set(prev);
            newSet.delete(message.payload.userId);
            return newSet;
          });
          break;

        case 'message_read':
          setMessages(prev =>
            prev.map(msg =>
              msg.id === message.payload.messageId
                ? { ...msg, read: true }
                : msg
            )
          );
          break;
      }
    },
  });

  // Send message
  const sendMessageToConversation = useCallback((content: string, type: 'text' | 'image' | 'file' = 'text') => {
    sendMessage('send_message', {
      conversationId,
      userId,
      content,
      type,
      timestamp: Date.now(),
    });
  }, [sendMessage, conversationId, userId]);

  // Mark message as read
  const markMessageRead = useCallback((messageId: string) => {
    sendMessage('mark_read', {
      conversationId,
      messageId,
      userId,
    });
  }, [sendMessage, conversationId, userId]);

  return {
    messages,
    onlineUsers,
    sendMessage: sendMessageToConversation,
    markMessageRead,
    isConnected,
  };
};

