        return;
      }

      setError(
        err?.message === 'auth-sign-in-timeout'
          ? 'Sign-in is taking too long. Please check Firebase/emulator connectivity and try again.'
          : formatAuthError(err?.code)
      );
    } finally {
      setLoading(false);
