        await sendMessage(
          childId,
          parentId,
          `${childName} shared today's mood: ${selectedMood?.icon || ''} ${selectedMood?.label || value}.`,
          'child',
          childId
        );
      }
      setNotice('Mood saved for today.', 'success');
