                <div key={ch.id} className="rounded-[1.2rem] border border-white/10 bg-white/[0.04] px-5 py-4 shadow-[0_10px_24px_rgba(2,6,23,0.25)]">
                  <p className="text-base font-bold">{ch.title}</p>
                  {ch.description && <p className={clsx('mt-1 text-sm leading-6', mutedTextClass)}>{ch.description}</p>}
                  <div className="mt-3 flex items-center gap-4">
                    <div className="flex-1">
                      <p className={clsx('text-xs font-bold', mutedTextClass)}>You: {ch.child_score}/{ch.target_score}</p>
                      <div className={clsx('h-3 rounded-full mt-1', isDark ? 'bg-white/10' : 'bg-indigo-100')}>
                        <div className="h-full rounded-full bg-[linear-gradient(90deg,#ec4899,#f472b6)] transition-all" style={{ width: `${Math.min(100, (ch.child_score / ch.target_score) * 100)}%` }} />
                      </div>
                    </div>
                    <div className="flex-1">
                      <p className={clsx('text-xs font-bold', mutedTextClass)}>Parent: {ch.parent_score}/{ch.target_score}</p>
                      <div className={clsx('h-3 rounded-full mt-1', isDark ? 'bg-white/10' : 'bg-indigo-100')}>
                        <div className="h-full rounded-full bg-[linear-gradient(90deg,#8b5cf6,#6366f1)] transition-all" style={{ width: `${Math.min(100, (ch.parent_score / ch.target_score) * 100)}%` }} />
                      </div>
                    </div>
                  </div>
                  <button onClick={() => void incrementChallengeScore(ch.id, 'child')} className="mt-3 rounded-xl bg-[linear-gradient(135deg,#ec4899,#8b5cf6)] px-4 py-2 text-xs font-bold uppercase tracking-[0.08em] text-white shadow-md transition hover:brightness-110">+1 My Score</button>
                </div>
              ))}
            </div>
          )}

          <div className={clsx('mt-5 rounded-[1.35rem] border p-4 shadow-[inset_0_1px_0_rgba(255,255,255,0.06)]', subPanelClass)}>
            <div className={clsx('flex flex-wrap items-center justify-between gap-3 text-[11px] font-black uppercase tracking-[0.14em]', softTextClass)}>
              <span>Adventure Meter</span>
              <div className="flex items-center gap-3"><span className={isDark ? 'text-amber-200' : 'text-amber-500'}>{'★'.repeat(Math.max(1, Math.min(5, Math.ceil(progressPercent / 20) || 1)))}</span><span>{progressPercent}%</span></div>
            </div>
            <div className="mt-4 h-4 rounded-full bg-white/10 p-1">
              <div className="h-full rounded-full bg-[linear-gradient(90deg,#5ee7ff_0%,#7c83ff_55%,#ff7bc0_100%)] transition-all" style={{ width: `${progressPercent}%` }} />
            </div>
          </div>
        </div>
        )}

        {uploading && (
          <div className={clsx('mt-4 rounded-2xl border px-4 py-3 text-sm font-semibold shadow-[0_10px_25px_rgba(14,165,233,0.12)]', isDark ? 'border-cyan-300/20 bg-cyan-400/10 text-cyan-100' : 'border-cyan-200 bg-cyan-50 text-cyan-700')}>
            <p>Uploading proof... {uploadProgress}%</p>
            <div className={clsx('mt-2 h-2 rounded-full', isDark ? 'bg-white/10' : 'bg-cyan-100')}>
              <div className="h-2 rounded-full bg-[linear-gradient(90deg,#22d3ee,#60a5fa)] transition-all duration-200" style={{ width: `${uploadProgress}%` }} />
            </div>
          </div>
        )}

        {!uploading && hasPendingRetry ? (
          <div className={clsx('mt-4 rounded-2xl border px-4 py-3 text-sm font-semibold shadow-[0_10px_25px_rgba(251,191,36,0.18)]', isDark ? 'border-amber-300/25 bg-amber-400/10 text-amber-100' : 'border-amber-200 bg-amber-50 text-amber-700')}>
            <p>Proof upload interrupted. Retry when ready.</p>
            <button onClick={() => void retryUpload()} className="mt-2 rounded-xl bg-amber-400/20 px-3 py-1.5 text-xs font-bold uppercase tracking-[0.08em]">
              Retry Upload
            </button>
          </div>
        ) : null}

        {questCelebration ? (
          <div className={clsx('mt-4 rounded-2xl border px-4 py-3 text-sm font-black shadow-[0_12px_30px_rgba(16,185,129,0.2)] animate-pulse', isDark ? 'border-emerald-300/30 bg-emerald-400/10 text-emerald-100' : 'border-emerald-200 bg-emerald-50 text-emerald-700')}>
            Quest complete: {questCelebration.title} • +{questCelebration.stars} stars
          </div>
        ) : null}


        <Outlet context={contextValue} />

        <div className="fixed inset-x-3 bottom-3 z-40 mx-auto max-w-lg md:hidden">
          <div className={clsx('flex gap-1 overflow-x-auto rounded-[1.6rem] border px-2 py-3 shadow-[0_18px_40px_rgba(0,0,0,0.28)] backdrop-blur-xl', navShellClass)}>
            {childTabs.map((tab) => {
              const Icon = tab.icon;
              const active = activeTab === tab.id;
              return (
                <button key={tab.id} onClick={() => goToTab(tab.id)} className={clsx('relative min-w-[72px] shrink-0 flex flex-col items-center gap-1 rounded-2xl px-2 py-1.5', active ? (isDark ? 'bg-white/10 text-cyan-300' : 'bg-white text-cyan-600') : lowContrastTextClass)}>
                  {tab.id === 'rewards' && rewardsAlert ? (
                    <span className="absolute right-2 top-1 h-2.5 w-2.5 rounded-full bg-rose-500 ring-2 ring-white dark:ring-slate-900" />
                  ) : null}
                  {tab.id === 'money-pot' && moneyPotAlert ? (
                    <span className="absolute right-2 top-1 h-2.5 w-2.5 rounded-full bg-emerald-400 ring-2 ring-white dark:ring-slate-900" />
                  ) : null}
                  {tab.id === 'profile' ? <span className="text-xl leading-none">{avatarEmoji}</span> : <Icon size={20} />}
                  <span className="text-[11px] font-black">{tab.label}</span>
                </button>
              );
            })}
            <button onClick={() => setIsInboxOpen(true)} className={clsx('relative min-w-[72px] shrink-0 flex flex-col items-center gap-1 rounded-2xl px-2 py-1.5', lowContrastTextClass)}>
              {messages.filter(m => !m.is_read).length > 0 && (
                <span className="absolute right-3 top-1 h-2.5 w-2.5 rounded-full bg-rose-500 ring-2 ring-white dark:ring-slate-900" />
              )}
              <Mail size={20} />
              <span className="text-[11px] font-black">Inbox</span>
            </button>
          </div>
        </div>

        {/* Sick Modal */}
        {isSickModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4 backdrop-blur-sm">
            <div className={clsx('w-full max-w-md overflow-hidden rounded-3xl border shadow-2xl', isDark ? 'bg-[#1a1f3c] border-white/10' : 'bg-white border-slate-200')}>
              <div className={clsx('px-6 py-5 border-b', isDark ? 'border-white/10' : 'border-slate-100')}>
                <h2 className={clsx('text-xl font-bold', isDark ? 'text-white' : 'text-slate-900')}>I'm Sick 🤒</h2>
                <p className={clsx('mt-1 text-sm', isDark ? 'text-white/60' : 'text-slate-500')}>Request sick leave to pause your routines and tasks.</p>
              </div>
              <div className="p-6 space-y-4">
                <div>
                  <label className={clsx('mb-1.5 block text-xs font-bold uppercase tracking-wider', isDark ? 'text-white/70' : 'text-slate-600')}>Start Date</label>
                  <input
                    type="date"
                    value={sickStartDate}
                    onChange={(e) => setSickStartDate(e.target.value)}
                    className={clsx('w-full rounded-xl border px-4 py-3 text-sm transition focus:ring-2 focus:ring-cyan-500/50 outline-none', isDark ? 'border-white/10 bg-black/20 text-white placeholder-white/30' : 'border-slate-300 bg-white text-slate-900')}
                  />
                </div>
                <div>
                  <label className={clsx('mb-1.5 block text-xs font-bold uppercase tracking-wider', isDark ? 'text-white/70' : 'text-slate-600')}>End Date</label>
                  <input
                    type="date"
                    value={sickEndDate}
                    onChange={(e) => setSickEndDate(e.target.value)}
                    className={clsx('w-full rounded-xl border px-4 py-3 text-sm transition focus:ring-2 focus:ring-cyan-500/50 outline-none', isDark ? 'border-white/10 bg-black/20 text-white placeholder-white/30' : 'border-slate-300 bg-white text-slate-900')}
                  />
                </div>
                <div>
                  <label className={clsx('mb-1.5 block text-xs font-bold uppercase tracking-wider', isDark ? 'text-white/70' : 'text-slate-600')}>Reason (Optional)</label>
                  <input
                    type="text"
                    value={sickReason}
                    onChange={(e) => setSickReason(e.target.value)}
                    placeholder="e.g. Fever, Cold"
                    className={clsx('w-full rounded-xl border px-4 py-3 text-sm transition focus:ring-2 focus:ring-cyan-500/50 outline-none', isDark ? 'border-white/10 bg-black/20 text-white placeholder-white/30' : 'border-slate-300 bg-white text-slate-900')}
                  />
                </div>
              </div>
              <div className={clsx('flex items-center justify-end gap-3 px-6 py-4 bg-black/20 border-t', isDark ? 'border-white/5' : 'border-slate-50')}>
                <button
                  onClick={() => setIsSickModalOpen(false)}
                  className={clsx('rounded-xl px-4 py-2 text-sm font-bold transition hover:bg-white/10', isDark ? 'text-white/70' : 'text-slate-600')}
                >
                  Cancel
                </button>
                <button
                  onClick={async () => {
                    try {
                      await initiateSickPeriod(childId, 'child', childId, sickStartDate, sickEndDate, sickReason);
                      addToast('Sick leave requested! Waiting for parent approval.', 'success');
                      await sendMessage(childId, parentId, `I've requested sick leave from ${sickStartDate} to ${sickEndDate}.`, 'child');
                      setIsSickModalOpen(false);
                    } catch (error) {
                      addToast('Failed to request sick leave.', 'error');
                    }
                  }}
                  className="rounded-xl bg-cyan-500 px-5 py-2 text-sm font-bold text-white shadow-lg shadow-cyan-500/30 transition hover:bg-cyan-400"
                >
                  Submit Request
                </button>
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

import { useMemo, useState } from 'react';
import clsx from 'clsx';
import { updatePassword } from 'firebase/auth';
import { addDoc, collection, doc, updateDoc } from 'firebase/firestore';
import { BadgeCheck, Lock, Sparkles, Star } from 'lucide-react';
import { auth, db } from '../../config/firebase';
import { useChildLayout } from './ChildLayout';
import ChildSpecialDates from './SpecialDates';
import ChildGrowth from './Growth';
import { calculateAgeFromDob } from '../../hooks/useCoreLogic';
import { getLevelProgress } from '../../utils/childProgression';

const AVATARS = ['🦊', '🐯', '🦁', '🐼', '🧠', '🚀', '🌟', '🐬'];
const PERSONALITY_TAGS = ['Animal lover', 'Book explorer', 'Science curious', 'Creative thinker', 'Fast finisher', 'Kind helper', 'Nature buddy', 'Puzzle solver'];
const STYLE_OPTIONS: Array<{ id: NonNullable<ReturnType<typeof useChildLayout>['profile']['communication_style']>; label: string; hint: string }> = [
  { id: 'cheerful', label: 'Cheerful', hint: 'Bright and excited' },
  { id: 'calm', label: 'Calm', hint: 'Soft and steady' },
  { id: 'challenge', label: 'Challenge me', hint: 'Push me a little' },
  { id: 'short', label: 'Short', hint: 'Quick and simple' }
];

export default function ChildProfile() {
  const { accentCaptionClass, isDark, mutedTextClass, panelClass, profile } = useChildLayout();
  const [profileTab, setProfileTab] = useState<'settings' | 'special-dates' | 'growth'>('settings');
  const [petName, setPetName] = useState(profile.pet_name || '');
  const [avatarEmoji, setAvatarEmoji] = useState(profile.avatar_emoji || '🦊');
  const [interests, setInterests] = useState((profile.interests || []).join(', '));
  const [personalityTags, setPersonalityTags] = useState<string[]>(profile.personality_tags || []);
  const [communicationStyle, setCommunicationStyle] = useState(profile.communication_style || 'cheerful');
  const [profileMotto, setProfileMotto] = useState(profile.profile_motto || '');
  const [newPassword, setNewPassword] = useState('');
  const [savingProfile, setSavingProfile] = useState(false);
  const [savingPassword, setSavingPassword] = useState(false);
  const [message, setMessage] = useState('');

  const age = useMemo(() => calculateAgeFromDob(profile.date_of_birth), [profile.date_of_birth]);
  const level = useMemo(() => getLevelProgress(Number(profile.total_stars || 0)), [profile.total_stars]);
  const displayName = petName.trim() || profile.name || 'Explorer';
  const pagePanelClass = isDark
    ? panelClass
    : 'border-slate-200 bg-white text-slate-950';
  const profileCardClass = isDark
    ? 'border-white/10 bg-white/6 text-white'
    : 'border-slate-200 bg-slate-50 text-slate-950 shadow-sm';
  const profileInputClass = isDark
    ? 'border-white/20 bg-white/5 text-white placeholder:text-white/35'
    : 'border-slate-300 bg-white text-slate-950 placeholder:text-slate-400';
  const inactiveTabClass = isDark
    ? 'border border-white/20 text-white'
    : 'border border-slate-300 bg-white text-slate-800 hover:bg-slate-50';
  const labelClass = isDark ? accentCaptionClass : 'text-cyan-600';
  const descriptionClass = isDark ? mutedTextClass : 'text-slate-600';

  const saveProfile = async () => {
    setSavingProfile(true);
    setMessage('');
    try {
      await updateDoc(doc(db, 'child_profile', profile.id), {
        pet_name: petName.trim() || null,
        avatar_emoji: avatarEmoji,
        interests: interests.split(',').map((x) => x.trim()).filter(Boolean).slice(0, 8),
        personality_tags: personalityTags.slice(0, 5),
        communication_style: communicationStyle,
        profile_motto: profileMotto.trim().slice(0, 90) || null,
        updated_at: new Date().toISOString()
      });
      setMessage('Profile updated. Great work!');
    } catch (error) {
      console.error('Failed to update profile:', error);
      setMessage('Could not update profile right now.');
    } finally {
      setSavingProfile(false);
    }
  };

  const togglePersonalityTag = (tag: string) => {
    setPersonalityTags((prev) => {
      if (prev.includes(tag)) return prev.filter((item) => item !== tag);
      return [...prev, tag].slice(0, 5);
    });
  };

  const savePassword = async () => {
    if (!newPassword.trim() || newPassword.trim().length < 6 || !auth.currentUser) return;
    setSavingPassword(true);
    setMessage('');
    try {
      await updatePassword(auth.currentUser, newPassword.trim());
      setNewPassword('');
      setMessage('Password updated successfully.');
    } catch (error: any) {
      console.error('Failed to update password:', error);
      if (String(error?.code || '').includes('requires-recent-login')) {
        setMessage('Please log out and log in again before updating password.');
      } else {
        setMessage('Could not update password right now.');
      }
    } finally {
      setSavingPassword(false);
    }
  };

  const requestParentReset = async () => {
    setMessage('');
    try {
      await addDoc(collection(db, 'messages'), {
        child_id: profile.id,
        parent_id: profile.family_id || profile.parent_id || '',
        subject: 'Password reset request',
        content: 'Please reset my login password.',
        sender_role: 'child',
        sender_id: profile.id,
        is_read: false,
        timestamp: new Date().toISOString()
      });
      setMessage('Password reset request sent to parent.');
    } catch (error) {
      console.error('Failed to request password reset:', error);
      setMessage('Could not send reset request.');
    }
  };

  return (
    <div className="mt-6 space-y-5">
      <div className={clsx('rounded-[1.75rem] border p-4 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', pagePanelClass)}>
        <div className="flex flex-wrap gap-2">
          <button type="button" onClick={() => setProfileTab('settings')} className={clsx('rounded-xl px-4 py-2 text-sm font-bold', profileTab === 'settings' ? 'bg-cyan-500 text-white' : inactiveTabClass)}>Profile Settings</button>
          <button type="button" onClick={() => setProfileTab('special-dates')} className={clsx('rounded-xl px-4 py-2 text-sm font-bold', profileTab === 'special-dates' ? 'bg-fuchsia-500 text-white' : inactiveTabClass)}>Special Dates</button>
          <button type="button" onClick={() => setProfileTab('growth')} className={clsx('rounded-xl px-4 py-2 text-sm font-bold', profileTab === 'growth' ? 'bg-emerald-500 text-white' : inactiveTabClass)}>Growth</button>
        </div>
      </div>

      {profileTab === 'settings' && (
        <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', pagePanelClass)}>
          <div className={clsx('rounded-[1.4rem] border p-5', isDark ? 'border-cyan-300/15 bg-cyan-400/8' : 'border-cyan-100 bg-cyan-50')}>
            <div className="flex flex-col gap-5 sm:flex-row sm:items-center sm:justify-between">
              <div className="flex items-center gap-4">
                <div className={clsx('grid h-20 w-20 place-items-center rounded-3xl border text-5xl shadow-lg', isDark ? 'border-white/12 bg-white/8' : 'border-cyan-100 bg-white')}>
                  {avatarEmoji}
                </div>
                <div>
                  <p className={clsx('text-xs font-black uppercase tracking-[0.18em]', labelClass)}>Explorer Identity</p>
                  <h2 className="mt-1 text-3xl font-display font-bold">{displayName}</h2>
                  <p className={clsx('mt-1 text-sm font-semibold', descriptionClass)}>
                    Full name: <span className={isDark ? 'text-white' : 'text-slate-900'}>{profile.name}</span>
                  </p>
                  {profileMotto.trim() ? (
                    <p className={clsx('mt-2 max-w-2xl text-sm italic', descriptionClass)}>"{profileMotto.trim()}"</p>
                  ) : null}
                </div>
              </div>
              <div className="grid grid-cols-3 gap-2 sm:min-w-[280px]">
                <div className={clsx('rounded-2xl border p-3 text-center', profileCardClass)}>
                  <Star className="mx-auto mb-1 fill-current text-amber-400" size={18} />
                  <p className="text-lg font-black">{profile.total_stars || 0}</p>
                  <p className={clsx('text-[10px] font-black uppercase tracking-wide', descriptionClass)}>Stars</p>
                </div>
                <div className={clsx('rounded-2xl border p-3 text-center', profileCardClass)}>
                  <BadgeCheck className="mx-auto mb-1 text-cyan-400" size={18} />
                  <p className="text-lg font-black">{level.levelName.split(' ')[0]}</p>
                  <p className={clsx('text-[10px] font-black uppercase tracking-wide', descriptionClass)}>Level</p>
                </div>
                <div className={clsx('rounded-2xl border p-3 text-center', profileCardClass)}>
                  <Sparkles className="mx-auto mb-1 text-fuchsia-400" size={18} />
                  <p className="text-lg font-black">{level.starsToNext}</p>
                  <p className={clsx('text-[10px] font-black uppercase tracking-wide', descriptionClass)}>Next</p>
                </div>
              </div>
            </div>
          </div>

          <h3 className="mt-6 text-xl font-display font-bold">Profile Settings</h3>
          <p className={clsx('mt-1 text-sm', descriptionClass)}>Choose how TikTrack sees you and talks with you.</p>

          <div className="mt-5 grid gap-3 sm:grid-cols-2 lg:grid-cols-5">
            <div className={clsx('min-w-0 rounded-2xl border px-3 py-3', profileCardClass)}>
              <p className={clsx('text-[11px] font-bold uppercase tracking-[0.14em]', labelClass)}>Avatar</p>
              <p className="mt-1 text-2xl font-bold">{avatarEmoji}</p>
            </div>
            <div className={clsx('min-w-0 rounded-2xl border px-3 py-3', profileCardClass)}>
              <p className={clsx('text-[11px] font-bold uppercase tracking-[0.14em]', labelClass)}>Age</p>
              <p className="mt-1 text-base font-bold">{age} years</p>
            </div>
            <div className={clsx('min-w-0 rounded-2xl border px-3 py-3', profileCardClass)}>
              <p className={clsx('text-[11px] font-bold uppercase tracking-[0.14em]', labelClass)}>Full Name</p>
              <p className="mt-1 truncate text-base font-bold">{profile.name}</p>
            </div>
            <div className={clsx('min-w-0 rounded-2xl border px-3 py-3', profileCardClass)}>
              <p className={clsx('text-[11px] font-bold uppercase tracking-[0.14em]', labelClass)}>Streak</p>
              <p className="mt-1 truncate text-base font-bold">{profile.streak_count || 0} days</p>
            </div>
            <div className={clsx('min-w-0 rounded-2xl border px-3 py-3', profileCardClass)}>
              <p className={clsx('text-[11px] font-bold uppercase tracking-[0.14em]', labelClass)}>Shields</p>
              <p className="mt-1 text-base font-bold">{profile.streak_shields || 0}</p>
            </div>
          </div>

          <div className="mt-5 grid gap-4 xl:grid-cols-2">
            <div className={clsx('rounded-[1.3rem] border px-4 py-4', profileCardClass)}>
              <p className={clsx('text-xs font-bold uppercase tracking-[0.18em]', labelClass)}>Identity</p>
              <label className={clsx('mt-3 block text-xs font-bold uppercase tracking-wide', descriptionClass)}>Call me</label>
              <input value={petName} onChange={(event) => setPetName(event.target.value)} placeholder="Nickname used in greetings" className={clsx('mt-1 w-full rounded-xl border px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-cyan-400/40', profileInputClass)} />
              <label className={clsx('mt-3 block text-xs font-bold uppercase tracking-wide', descriptionClass)}>Full name</label>
              <div className={clsx('mt-1 flex items-center gap-2 rounded-xl border px-3 py-2 text-sm', isDark ? 'border-white/10 bg-white/5 text-white/70' : 'border-slate-200 bg-slate-100 text-slate-600')}>
                <Lock size={13} />
                <span>{profile.name}</span>
                <span className="ml-auto text-[10px] font-bold uppercase">Parent managed</span>
              </div>
              <div className="mt-3 flex flex-wrap gap-2">
                {AVATARS.map((emoji) => (
                  <button key={emoji} type="button" onClick={() => setAvatarEmoji(emoji)} className={clsx('rounded-xl border px-3 py-1.5 text-xl', avatarEmoji === emoji ? 'border-cyan-300 bg-cyan-500/15' : isDark ? 'border-white/20' : 'border-slate-300 bg-white')}>{emoji}</button>
                ))}
              </div>
              <input value={profileMotto} onChange={(event) => setProfileMotto(event.target.value)} placeholder="One line about me" maxLength={90} className={clsx('mt-3 w-full rounded-xl border px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-cyan-400/40', profileInputClass)} />
              <input value={interests} onChange={(event) => setInterests(event.target.value)} placeholder="Interests (comma separated)" className={clsx('mt-3 w-full rounded-xl border px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-cyan-400/40', profileInputClass)} />
              <div className="mt-3 flex flex-wrap gap-2">
                {PERSONALITY_TAGS.map((tag) => {
                  const selected = personalityTags.includes(tag);
                  return (
                    <button key={tag} type="button" onClick={() => togglePersonalityTag(tag)} className={clsx('rounded-full border px-3 py-1.5 text-xs font-bold transition', selected ? 'border-cyan-300 bg-cyan-500/15 text-cyan-300' : isDark ? 'border-white/15 text-white/65 hover:bg-white/5' : 'border-slate-300 bg-white text-slate-600 hover:bg-slate-50')}>
                      {tag}
                    </button>
                  );
                })}
              </div>
              <div className="mt-3 grid grid-cols-2 gap-2">
                {STYLE_OPTIONS.map((style) => (
                  <button key={style.id} type="button" onClick={() => setCommunicationStyle(style.id)} className={clsx('rounded-xl border px-3 py-2 text-left transition', communicationStyle === style.id ? 'border-fuchsia-300 bg-fuchsia-500/15' : isDark ? 'border-white/15 hover:bg-white/5' : 'border-slate-300 bg-white hover:bg-slate-50')}>
                    <span className="block text-sm font-black">{style.label}</span>
                    <span className={clsx('text-xs', descriptionClass)}>{style.hint}</span>
                  </button>
                ))}
              </div>
              <button type="button" onClick={() => void saveProfile()} disabled={savingProfile} className="mt-3 rounded-xl bg-cyan-500 px-4 py-2 text-sm font-bold text-white disabled:opacity-60">{savingProfile ? 'Saving...' : 'Save Profile'}</button>
            </div>

            <div className={clsx('rounded-[1.3rem] border px-4 py-4', profileCardClass)}>
              <p className={clsx('text-xs font-bold uppercase tracking-[0.18em]', labelClass)}>Password</p>
              <input type="password" value={newPassword} onChange={(event) => setNewPassword(event.target.value)} placeholder="New password (min 6 chars)" className={clsx('mt-3 w-full rounded-xl border px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-400/40', profileInputClass)} />
              <div className="mt-3 flex flex-wrap gap-2">
                <button type="button" onClick={() => void savePassword()} disabled={savingPassword || newPassword.trim().length < 6} className="rounded-xl bg-indigo-500 px-4 py-2 text-sm font-bold text-white disabled:opacity-60">{savingPassword ? 'Updating...' : 'Update Password'}</button>
                <button type="button" onClick={() => void requestParentReset()} className={clsx('rounded-xl border px-4 py-2 text-sm font-bold', isDark ? 'border-white/20 text-white' : 'border-slate-300 bg-white text-slate-800')}>Request Parent Reset</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {profileTab === 'special-dates' && <ChildSpecialDates />}
      {profileTab === 'growth' && <ChildGrowth />}

      {message ? <div className={clsx('rounded-xl border px-4 py-3 text-sm font-semibold', isDark ? 'border-cyan-300/20 bg-cyan-400/10 text-cyan-100' : 'border-cyan-200 bg-cyan-50 text-cyan-700')}>{message}</div> : null}
    </div>
  );
}

import { useEffect, useMemo, useState } from 'react';
import clsx from 'clsx';
import { collection, getDocs, query, where } from 'firebase/firestore';
import RewardMarketplace from '../../components/RewardMarketplace';
import { db } from '../../config/firebase';
import { useRedemptions, useRewards } from '../../hooks/useRedemptions';
import { useRewardLedger } from '../../hooks/useRewardLedger';
import { useScratchRewards } from '../../hooks/useScratchRewards';
import { useChildLayout } from './ChildLayout';
import { computeMonthlyStars, getChildBadges, getLevelProgress } from '../../utils/childProgression';
import type { RewardItem, RewardLedgerEntry, ScratchRewardCard } from '../../types/schema';

export default function ChildRewards() {
  const { panelClass, mutedTextClass, profile, tasks } = useChildLayout();
  const parentId = profile.family_id || profile.parent_id || '';
  const { rewards, loading: rewardsLoading } = useRewards(parentId);
  const { redemptions, requestRedemption } = useRedemptions(profile.id, parentId);
  const { visibleEntries, surpriseEntries, loading: ledgerLoading, revealEntry } = useRewardLedger(profile.id, parentId);
  const { availableCards, loading: scratchLoading, revealScratchCard } = useScratchRewards(profile.id, parentId);

  const [monthlyEarnedStars, setMonthlyEarnedStars] = useState(0);
  const [conversionRate, setConversionRate] = useState(1);
  const [loadingSummary, setLoadingSummary] = useState(true);
  const [redemptionMode, setRedemptionMode] = useState<'cash' | 'rewards'>('cash');
  const [cashStars, setCashStars] = useState<number | ''>('');
  const [cashRequesting, setCashRequesting] = useState(false);
  const [cashMessage, setCashMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
  const [openingGiftId, setOpeningGiftId] = useState<string | null>(null);
  const [openedScratch, setOpenedScratch] = useState<ScratchRewardCard | null>(null);

  const level = useMemo(() => getLevelProgress(Number(profile.total_stars || 0)), [profile.total_stars]);
  const pendingRewards = useMemo(() => redemptions.filter((item) => item.status === 'pending').length, [redemptions]);

  const badges = useMemo(() => getChildBadges({
    consistencyScore: Number(profile.consistency_score || 0),
    streakCount: Number(profile.streak_count || 0),
    earlyBirdCompletions: Number(profile.early_bird_count || 0),
    readingCompletions: Number(profile.reading_completed_count || 0),
    studyCompletions: Number(profile.study_completed_count || 0),
    perfectWeekCount: Number(profile.perfect_week_count || 0)
  }), [profile.consistency_score, profile.early_bird_count, profile.perfect_week_count, profile.reading_completed_count, profile.streak_count, profile.study_completed_count]);

  useEffect(() => {
    const loadSummary = async () => {
      setLoadingSummary(true);
      try {
        const now = new Date();
        const from = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
        const to = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().slice(0, 10);

        const [tasksSnap, logsSnap, rewardSettingsByFamilySnap, rewardSettingsByParentSnap] = await Promise.all([
          getDocs(query(collection(db, 'tasks'), where('child_id', '==', profile.id))),
          getDocs(query(collection(db, 'task_logs'), where('child_id', '==', profile.id), where('status', '==', 'completed'), where('date', '>=', from), where('date', '<=', to))),
          getDocs(query(collection(db, 'reward_settings'), where('family_id', '==', parentId))),
          getDocs(query(collection(db, 'reward_settings'), where('parent_id', '==', parentId)))
        ]);

        const taskStarMap = new Map<string, number>();
        tasksSnap.docs.forEach((docSnap) => {
          const data = docSnap.data() as any;
          taskStarMap.set(docSnap.id, Number(data.points ?? data.star_value ?? 0));
        });

        const logs = logsSnap.docs.map((docSnap) => docSnap.data() as { date: string; status: string; task_id: string });
        setMonthlyEarnedStars(computeMonthlyStars(logs, taskStarMap, now));

        const rewardSettingDoc = rewardSettingsByFamilySnap.docs[0] || rewardSettingsByParentSnap.docs[0];
        if (rewardSettingDoc) {
          const raw = rewardSettingDoc.data() as any;
          const savedRate = Number(raw.star_to_currency_rate);
          setConversionRate(Number.isFinite(savedRate) ? Math.max(0, savedRate) : 1);
        }
      } finally {
        setLoadingSummary(false);
      }
    };

    void loadSummary();
  }, [parentId, profile.id, tasks]);

  const monthlySpentStars = useMemo(() => {
    const now = new Date();
    return redemptions
      .filter((redemption) => {
        const ts = new Date(redemption.requested_at);
        return ts.getFullYear() === now.getFullYear() && ts.getMonth() === now.getMonth();
      })
      .reduce((sum, redemption) => sum + Number(redemption.stars_spent || 0), 0);
  }, [redemptions]);

  const monthlyPayoutEstimate = useMemo(() => Number((monthlyEarnedStars * conversionRate).toFixed(2)), [conversionRate, monthlyEarnedStars]);
  const availableStars = Number(profile.total_stars || 0);
  const cashStarsValue = cashStars === '' ? 0 : Number(cashStars);
  const cashEstimate = Number((cashStarsValue * conversionRate).toFixed(2));
  const unlockedBadges = useMemo(() => badges.filter((badge) => badge.unlocked).length, [badges]);
  const nextBadge = useMemo(() => badges.find((badge) => !badge.unlocked) || null, [badges]);
  const openedGift = useMemo(
    () => visibleEntries.find((entry) => entry.id === openingGiftId) || null,
    [openingGiftId, visibleEntries]
  );
  const timelineGroups = useMemo(() => {
    const groups = new Map<string, RewardLedgerEntry[]>();
    visibleEntries
      .filter((entry) => entry.surprise_state !== 'hidden')
      .forEach((entry) => {
        const dateKey = new Date(entry.created_at).toISOString().slice(0, 10);
        groups.set(dateKey, [...(groups.get(dateKey) || []), entry]);
      });

    return Array.from(groups.entries()).map(([date, items]) => ({ date, items }));
  }, [visibleEntries]);

  const requestCashRedemption = async () => {
    if (!cashStarsValue || cashStarsValue <= 0) {
      setCashMessage({ type: 'error', text: 'Choose how many stars to redeem for cash.' });
      return;
    }

    if (cashStarsValue > availableStars) {
      setCashMessage({ type: 'error', text: `You only have ${availableStars} stars available.` });
      return;
    }

    const now = new Date().toISOString();
    const cashReward: RewardItem = {
      id: `cash_${profile.id}_${Date.now()}`,
      parent_id: parentId,
      family_id: parentId,
      child_id: profile.id,
      name: 'Cash payout',
      description: `${cashStarsValue} stars at ${conversionRate} cash value per star = ${cashEstimate}`,
      star_cost: cashStarsValue,
      icon: '💰',
      category: 'cash',
      is_available: true,
      created_at: now,
      updated_at: now
    };

    setCashRequesting(true);
    try {
      await requestRedemption(cashReward.id, cashReward, availableStars);
      setCashMessage({ type: 'success', text: 'Cash request sent for parent approval.' });
      setCashStars('');
      setTimeout(() => setCashMessage(null), 3000);
    } catch (error) {
      setCashMessage({ type: 'error', text: error instanceof Error ? error.message : 'Could not send cash request.' });
    } finally {
      setCashRequesting(false);
    }
  };

  const openSurpriseGift = async (entry: RewardLedgerEntry) => {
    await revealEntry(entry.id);
    setOpeningGiftId(entry.id);
  };

  const openScratchReward = async (cardId: string) => {
    const revealed = await revealScratchCard(cardId);
    if (revealed) {
      setOpenedScratch(revealed);
    }
  };

  const getTimelineTypeLabel = (entry: RewardLedgerEntry) => {
    if (entry.type === 'task_completed') return 'Task';
    if (entry.type === 'manual_award') return 'Gift';
    if (entry.type === 'scratch_reward') return 'Scratch';
    if (entry.type === 'redemption') return 'Redeemed';
    if (entry.type === 'bonus') return 'Bonus';
    return 'Update';
  };

  return (
    <div className="mt-6 space-y-5 pb-20">
      <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', panelClass)}>
        <h2 className="text-3xl font-display font-bold">Stars & Rewards</h2>
        <p className={clsx('mt-1 text-sm', mutedTextClass)}>Earn stars, request cash, or spend stars on rewards.</p>

        {loadingSummary ? <p className={clsx('mt-3 text-sm', mutedTextClass)}>Loading progress summary...</p> : null}

        <div className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-6">
          <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Total Stars</p><p className="mt-1 text-2xl font-black">{profile.total_stars || 0}</p></div>
          <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Monthly Stars</p><p className="mt-1 text-2xl font-black">{monthlyEarnedStars}</p></div>
          <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Cash Estimate</p><p className="mt-1 text-2xl font-black">{monthlyPayoutEstimate}</p></div>
          <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Stars Spent</p><p className="mt-1 text-2xl font-black">{monthlySpentStars}</p></div>
          <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Streak / Shields</p><p className="mt-1 text-2xl font-black">{profile.streak_count || 0} / {profile.streak_shields || 0}</p></div>
          <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Pending Rewards</p><p className="mt-1 text-2xl font-black">{pendingRewards}</p></div>
        </div>

        <div className="mt-4 grid gap-3 lg:grid-cols-[1.6fr_1fr]">
          <div className="rounded-xl border border-cyan-300/20 bg-cyan-500/10 p-3">
            <p className="text-xs font-bold uppercase tracking-[0.12em] text-cyan-200">Level Progress</p>
            <div className="mt-1 flex flex-wrap items-end justify-between gap-2">
              <p className="text-lg font-bold">{level.levelName}</p>
              <p className="text-sm text-cyan-100/90">{level.nextLevelName ? `${level.starsToNext} stars to ${level.nextLevelName}` : 'Top level unlocked'}</p>
            </div>
            <div className="mt-2 h-2 rounded-full bg-white/10 p-[2px]"><div className="h-full rounded-full bg-[linear-gradient(90deg,#22d3ee,#818cf8,#f472b6)] transition-all" style={{ width: `${level.progressPct}%` }} /></div>
          </div>
          <div className="rounded-xl border border-amber-300/20 bg-amber-500/10 p-3">
            <p className="text-xs font-bold uppercase tracking-[0.12em] text-amber-200">Badges</p>
            <p className="mt-1 text-lg font-bold">{unlockedBadges} / {badges.length} unlocked</p>
            <p className="text-sm text-amber-100/90">{nextBadge ? `Next: ${nextBadge.label}` : 'All badges unlocked'}</p>
          </div>
        </div>
      </div>

      <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', panelClass)}>
        <h3 className="text-2xl font-display font-bold">Redeem Stars</h3>
        <div className="mt-4 grid grid-cols-2 gap-2 rounded-xl border border-white/10 bg-white/[0.04] p-1">
          <button
            type="button"
            onClick={() => setRedemptionMode('cash')}
            className={clsx('rounded-lg px-3 py-2 text-sm font-black transition', redemptionMode === 'cash' ? 'bg-emerald-400 text-slate-950' : mutedTextClass)}
          >
            Cash Request
          </button>
          <button
            type="button"
            onClick={() => setRedemptionMode('rewards')}
            className={clsx('rounded-lg px-3 py-2 text-sm font-black transition', redemptionMode === 'rewards' ? 'bg-cyan-400 text-slate-950' : mutedTextClass)}
          >
            Reward Items
          </button>
        </div>

        {redemptionMode === 'cash' ? (
          <div className="mt-4 rounded-xl border border-emerald-300/20 bg-emerald-500/10 p-4">
            <div className="grid gap-3 sm:grid-cols-3">
              <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Available Stars</p><p className="mt-1 text-lg font-black">{availableStars}</p></div>
              <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Cash Rate</p><p className="mt-1 text-lg font-black">1 star = {conversionRate}</p></div>
              <div className="rounded-xl border border-white/10 bg-white/[0.04] px-4 py-3"><p className={clsx('text-xs font-bold uppercase', mutedTextClass)}>Cash Estimate</p><p className="mt-1 text-lg font-black">{cashEstimate}</p></div>
            </div>

            <div className="mt-4 flex flex-col gap-3 sm:flex-row">
              <input
                type="number"
                min="1"
                max={availableStars}
                value={cashStars as any}
                onChange={(event) => setCashStars(event.target.value === '' ? '' : Number(event.target.value))}
                placeholder="Stars to redeem as cash"
                className="min-w-0 flex-1 rounded-xl border border-white/10 bg-white/[0.08] px-4 py-3 text-sm font-bold outline-none"
              />
              <button
                type="button"
                onClick={() => void requestCashRedemption()}
                disabled={cashRequesting || availableStars <= 0}
                className="rounded-xl bg-emerald-400 px-5 py-3 text-sm font-black text-slate-950 disabled:opacity-50"
              >
                {cashRequesting ? 'Sending...' : 'Request Cash'}
              </button>
            </div>

            {cashMessage ? (
              <p className={clsx('mt-3 rounded-lg px-3 py-2 text-sm font-bold', cashMessage.type === 'success' ? 'bg-emerald-400/15 text-emerald-200' : 'bg-rose-400/15 text-rose-200')}>
                {cashMessage.text}
              </p>
            ) : null}
          </div>
        ) : (
          <div className="mt-4">
            <RewardMarketplace
              rewards={rewards}
              childProfile={profile}
              onRedeemReward={async (rewardId, reward) => {
                await requestRedemption(rewardId, reward, profile.total_stars || 0);
              }}
              loading={rewardsLoading}
            />
          </div>
        )}
      </div>

      {surpriseEntries.length > 0 ? (
        <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', panelClass)}>
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h3 className="text-2xl font-display font-bold">Surprise Gifts</h3>
              <p className={clsx('mt-1 text-sm', mutedTextClass)}>Parent sent something special. Open it when you are ready.</p>
            </div>
            <p className="rounded-full border border-pink-300/30 bg-pink-400/10 px-3 py-1 text-sm font-black text-pink-200">
              {surpriseEntries.length} unopened
            </p>
          </div>

          <div className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-3">
            {surpriseEntries.map((entry) => (
              <button
                key={entry.id}
                type="button"
                onClick={() => void openSurpriseGift(entry)}
                className="rounded-2xl border border-pink-300/25 bg-pink-500/10 px-4 py-4 text-left transition hover:bg-pink-500/15"
              >
                <p className="text-4xl">🎁</p>
                <p className="mt-2 text-lg font-black">Surprise gift</p>
                <p className={clsx('mt-1 text-sm', mutedTextClass)}>Tap to reveal your stars and message.</p>
              </button>
            ))}
          </div>
        </div>
      ) : null}

      {availableCards.length > 0 || scratchLoading ? (
        <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', panelClass)}>
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <h3 className="text-2xl font-display font-bold">Scratch Rewards</h3>
              <p className={clsx('mt-1 text-sm', mutedTextClass)}>Scratch a card to reveal the prize parent picked for you.</p>
            </div>
            <p className="rounded-full border border-violet-300/30 bg-violet-400/10 px-3 py-1 text-sm font-black text-violet-200">
              {availableCards.length} ready
            </p>
          </div>

          <div className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-3">
            {scratchLoading ? (
              <p className={mutedTextClass}>Loading scratch rewards...</p>
            ) : (
              availableCards.map((card) => (
                <button
                  key={card.id}
                  type="button"
                  onClick={() => void openScratchReward(card.id)}
                  className="rounded-2xl border border-violet-300/25 bg-violet-500/10 px-4 py-4 text-left transition hover:bg-violet-500/15"
                >
                  <p className="text-4xl">🎟️</p>
                  <p className="mt-2 text-lg font-black">{card.title}</p>
                  <p className={clsx('mt-1 text-sm', mutedTextClass)}>{card.reason}</p>
                </button>
              ))
            )}
          </div>
        </div>
      ) : null}

      <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', panelClass)}>
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div>
            <h3 className="text-2xl font-display font-bold">Badges</h3>
            <p className={clsx('mt-1 text-sm', mutedTextClass)}>Small milestones that track consistency, routines, and learning habits.</p>
          </div>
          <p className="rounded-full border border-amber-300/30 bg-amber-400/10 px-3 py-1 text-sm font-black text-amber-200">
            {unlockedBadges} / {badges.length} unlocked
          </p>
        </div>
        <div className="mt-4 grid gap-3 sm:grid-cols-2 xl:grid-cols-5">
          {badges.map((badge) => (
            <div key={badge.id} className={clsx('rounded-xl border px-3 py-3', badge.unlocked ? 'border-emerald-300/35 bg-emerald-500/10' : 'border-white/10 bg-white/[0.03]')}>
              <div className="flex items-start justify-between gap-2">
                <div>
                  <p className="text-2xl">{badge.icon}</p>
                  <p className="mt-1 font-bold">{badge.label}</p>
                </div>
                <p className={clsx('text-xs font-black', badge.unlocked ? 'text-emerald-300' : mutedTextClass)}>{badge.unlocked ? 'Unlocked' : badge.valueLabel}</p>
              </div>
              <div className="mt-3 h-2 rounded-full bg-white/10 p-[2px]">
                <div className={clsx('h-full rounded-full transition-all', badge.unlocked ? 'bg-emerald-300' : 'bg-amber-300')} style={{ width: `${badge.progressPct}%` }} />
              </div>
              <p className={clsx('mt-2 text-xs', mutedTextClass)}>{badge.unlocked ? badge.valueLabel : badge.hint}</p>
            </div>
          ))}
        </div>

      </div>

      <div className={clsx('rounded-[1.75rem] border p-5 shadow-[0_18px_45px_rgba(0,0,0,0.16)]', panelClass)}>
        <div className="flex flex-wrap items-end justify-between gap-3">
          <div>
            <h3 className="text-2xl font-display font-bold">Reward Timeline</h3>
            <p className={clsx('mt-1 text-sm', mutedTextClass)}>Track stars earned, gifts received, and rewards redeemed by date.</p>
          </div>
          <p className="rounded-full border border-cyan-300/30 bg-cyan-400/10 px-3 py-1 text-sm font-black text-cyan-200">
            {visibleEntries.length} entries
          </p>
        </div>

        <div className="mt-4 space-y-4">
          {ledgerLoading ? (
            <p className={mutedTextClass}>Loading reward timeline...</p>
          ) : timelineGroups.length === 0 ? (
            <p className={mutedTextClass}>No reward timeline yet. Complete tasks or open gifts to start tracking.</p>
          ) : (
            timelineGroups.slice(0, 8).map((group) => (
              <div key={group.date} className="relative pl-5">
                <div className="absolute left-[5px] top-7 bottom-0 w-px bg-white/10" />
                <div className="mb-2 flex items-center gap-2">
                  <span className="relative z-10 h-3 w-3 rounded-full bg-cyan-300 shadow-[0_0_0_4px_rgba(34,211,238,0.12)]" />
                  <p className="text-sm font-black">{new Date(group.date).toLocaleDateString(undefined, { month: 'short', day: 'numeric', year: 'numeric' })}</p>
                </div>
                <div className="space-y-2">
                  {group.items.map((entry) => {
                    const isPositive = entry.stars_delta >= 0;
                    return (
                      <div key={entry.id} className="rounded-[1.1rem] border border-white/10 bg-white/[0.03] px-3 py-3">
                        <div className="flex items-start justify-between gap-3">
                          <div className="min-w-0">
                            <div className="flex flex-wrap items-center gap-2">
                              <span className={clsx('rounded-full px-2 py-0.5 text-[11px] font-black uppercase', isPositive ? 'bg-emerald-400/15 text-emerald-200' : 'bg-amber-400/15 text-amber-200')}>
                                {getTimelineTypeLabel(entry)}
                              </span>
                              <span className={clsx('text-xs', mutedTextClass)}>
                                {new Date(entry.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                              </span>
                            </div>
                            <p className="mt-1 font-bold">{entry.title}</p>
                            <p className={clsx('mt-1 text-xs', mutedTextClass)}>{entry.reason}</p>
                          </div>
                          <p className={clsx('shrink-0 text-right text-lg font-black', isPositive ? 'text-emerald-300' : 'text-amber-300')}>
                            {isPositive ? '+' : ''}{entry.stars_delta}
                          </p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {openedGift ? (
        <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/70 px-4">
          <div className="w-full max-w-md rounded-[1.5rem] border border-pink-300/30 bg-slate-950 p-6 text-center shadow-2xl">
            <p className="text-5xl">🎁</p>
            <h3 className="mt-3 text-2xl font-display font-black">Surprise unlocked</h3>
            <p className="mt-2 text-3xl font-black text-emerald-300">+{openedGift.stars_delta} stars</p>
            <p className={clsx('mt-3 text-sm', mutedTextClass)}>{openedGift.reason}</p>
            <button
              type="button"
              onClick={() => setOpeningGiftId(null)}
              className="mt-5 rounded-xl bg-pink-400 px-5 py-3 text-sm font-black text-slate-950"
            >
              Yay
            </button>
          </div>
        </div>
      ) : null}

      {openedScratch ? (
        <div className="fixed inset-0 z-50 grid place-items-center bg-slate-950/70 px-4">
          <div className="w-full max-w-md rounded-[1.5rem] border border-violet-300/30 bg-slate-950 p-6 text-center shadow-2xl">
            <p className="text-5xl">🎟️</p>
            <h3 className="mt-3 text-2xl font-display font-black">Scratch reward</h3>
            <p className="mt-2 text-3xl font-black text-violet-200">{openedScratch.prize_label}</p>
            <p className={clsx('mt-3 text-sm', mutedTextClass)}>{openedScratch.reason}</p>
            <button
              type="button"
              onClick={() => setOpenedScratch(null)}
              className="mt-5 rounded-xl bg-violet-400 px-5 py-3 text-sm font-black text-slate-950"
            >
              Nice
            </button>
          </div>
        </div>
      ) : null}
    </div>
  );
}

import React, { useEffect, useState } from 'react';
import { useOutletContext } from 'react-router-dom';
import clsx from 'clsx';
import { CheckCircle2, Flame, Star, Lock, Plus, X, Clock } from 'lucide-react';
import type { ChildLayoutContextValue } from './ChildLayout';
import { useRoutines, getTodayDayRange } from '../../hooks/useRoutines';
import { useToast } from '../../contexts/ToastContext';
import type { Routine, RoutineLog } from '../../types/schema';

/** Returns e.g. "07:30 AM" from "07:30" */
function fmtTime(t: string) {
  if (!t) return '';
  const [h, m] = t.split(':').map(Number);
  const ampm = h >= 12 ? 'PM' : 'AM';
  const h12 = h % 12 || 12;
  return `${h12}:${String(m).padStart(2, '0')} ${ampm}`;
}

function currentTimeInputValue() {
  const now = new Date();
  return `${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`;
}

function todayKey() {
  const now = new Date();
  return `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
}

const EMPTY_FORM = {
  title: '',
  startTime: '07:00',
  endTime: '08:00',
  points: '' as number | '',
  icon: '📝',
  dayRange: 'everyday' as Routine['day_range'],
};

export default function RoutinePage() {
  const { profile, childId, familyId, isDark } = useOutletContext<ChildLayoutContextValue>();
  const { routines, loading, logRoutine, getTodayLogs, createRoutine } = useRoutines(familyId, childId);
  const { addToast } = useToast();

  const [todayLogs, setTodayLogs] = useState<Record<string, RoutineLog>>({});
  const [loggingId, setLoggingId] = useState<string | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);
  const [form, setForm] = useState({ ...EMPTY_FORM });
  const [saving, setSaving] = useState(false);
  const [completionRoutine, setCompletionRoutine] = useState<Routine | null>(null);
  const [actualCompletionTime, setActualCompletionTime] = useState(currentTimeInputValue);
  const [starCelebration, setStarCelebration] = useState<{ title: string; stars: number } | null>(null);
  const [processedLockoutDate, setProcessedLockoutDate] = useState('');

  const todayRange = getTodayDayRange();
  const dayLabel = todayRange === 'weekday' ? 'Weekday' : 'Weekend';
  const now = new Date();
  const isPastLockout = now.getHours() >= 22; // 10 PM lockout

  // Fetch today's logs
  useEffect(() => {
    if (!childId) return;
    getTodayLogs(childId).then(logs => {
      const logMap: Record<string, RoutineLog> = {};
      logs.forEach(log => { logMap[log.routine_id] = log; });
      setTodayLogs(logMap);
    }).catch(console.error);
  }, [childId, routines]);

  // Filter routines to today's day range
  const todayRoutines = routines.filter(r =>
    r.status === 'active' && (r.day_range === 'everyday' || r.day_range === todayRange)
  );

  // Build timeline: sort by start_time
  const timeline = [...todayRoutines].sort((a, b) =>
    (a.start_time || a.schedule_time || '').localeCompare(b.start_time || b.schedule_time || '')
  );

  const handleComplete = async (routineId: string) => {
    if (!childId) return;
    const routine = routines.find(r => r.id === routineId);
    if (!routine) return;

    if (isPastLockout) {
      addToast('⏰ It\'s past 10 PM — this routine is locked for today.', 'warning');
      return;
    }

    setActualCompletionTime(currentTimeInputValue());
    setCompletionRoutine(routine);
  };

  const submitCompletionTime = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!childId || !completionRoutine) return;
    const routine = completionRoutine;
    setLoggingId(routine.id);
    try {
      const result = await logRoutine(routine, childId, 'completed', actualCompletionTime);
      const newLog: RoutineLog = {
        id: `${childId}_${routine.id}_${todayKey()}`,
        routine_id: routine.id,
        family_id: familyId || '',
        child_id: childId,
        date: todayKey(),
        status: 'completed',
        completed_at: new Date().toISOString(),
        actual_completed_time: actualCompletionTime,
        in_time_window: result.inTimeWindow,
        stars_awarded: result.starsAwarded,
        stars_delta: result.starsDelta,
      };
      setTodayLogs(prev => ({ ...prev, [routine.id]: newLog }));

      if (!result.inTimeWindow) {
        addToast(`${routine.title} is marked done, but it was outside ${fmtTime(routine.start_time || routine.schedule_time || '')} - ${fmtTime(routine.end_time || '')}. No stars this time.`, 'warning');
      } else if (routine.requires_approval) {
        addToast(`✅ ${routine.title} submitted for parent approval!`, 'info');
      } else {
        addToast(`🌟 Awesome! ${routine.title} done — +${result.starsAwarded} stars!`, 'success');
        if (result.starsAwarded > 0) {
          setStarCelebration({ title: routine.title, stars: result.starsAwarded });
          window.setTimeout(() => setStarCelebration(null), 2400);
        }
      }
      setCompletionRoutine(null);
    } catch {
      addToast('Failed to log routine. Please try again.', 'error');
    } finally {
      setLoggingId(null);
    }
  };

  useEffect(() => {
    if (!childId || !familyId || !isPastLockout || loading || timeline.length === 0) return;
    const dateKey = todayKey();
    if (processedLockoutDate === dateKey) return;

    const pendingRoutines = timeline.filter((routine) => {
      const log = todayLogs[routine.id];
      return !log || (log.status !== 'completed' && log.status !== 'sick' && log.status !== 'missed');
    });

    if (pendingRoutines.length === 0) {
      setProcessedLockoutDate(dateKey);
      return;
    }

    setProcessedLockoutDate(dateKey);
    void (async () => {
      let deductedStars = 0;
      for (const routine of pendingRoutines) {
        try {
          const result = await logRoutine(routine, childId, 'missed');
          deductedStars += Math.abs(result.starsDelta);
          setTodayLogs((prev) => ({
            ...prev,
            [routine.id]: {
              id: `${childId}_${routine.id}_${dateKey}`,
              routine_id: routine.id,
              family_id: familyId,
              child_id: childId,
              date: dateKey,
              status: 'missed',
              stars_awarded: 0,
              stars_delta: result.starsDelta,
            }
          }));
        } catch (error) {
          console.warn('Failed to apply missed routine penalty:', error);
        }
      }
      if (deductedStars > 0) {
        addToast(`Daily routine lockout applied. ${deductedStars} stars deducted for missed routines.`, 'warning');
      }
    })();
  }, [addToast, childId, familyId, isPastLockout, loading, logRoutine, processedLockoutDate, timeline, todayLogs]);

  const handleAddRoutine = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!familyId || !childId) return;
    if (!form.title || !form.startTime || !form.endTime || form.points === '') {
      addToast('Please fill all required fields.', 'error');
      return;
    }
    if (form.endTime <= form.startTime) {
      addToast('End time must be after start time.', 'error');
      return;
    }
    setSaving(true);
    try {
      await createRoutine({
        family_id: familyId,
        child_id: childId,
        title: form.title.trim(),
        start_time: form.startTime,
        end_time: form.endTime,
        day_range: form.dayRange,
        points: Number(form.points),
        icon: form.icon || '📝',
        requires_approval: true, // child-created always needs parent approval
        created_by: 'child',
        status: 'active',
      });
      addToast('Routine added! Your parent will review it.', 'success');
      setForm({ ...EMPTY_FORM });
      setShowAddModal(false);
    } catch {
      addToast('Failed to create routine.', 'error');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <p className={clsx('animate-pulse font-bold text-sm', isDark ? 'text-white/60' : 'text-slate-400')}>
          Loading routines...
        </p>
      </div>
    );
  }

  const completedCount = timeline.filter(r => todayLogs[r.id]?.status === 'completed').length;
  const pendingCount = Math.max(timeline.length - completedCount, 0);

  return (
    <div className="mx-auto max-w-4xl pb-28 px-1">
      <div className={clsx('mb-5 rounded-2xl border p-4', isDark ? 'border-white/10 bg-white/[0.04]' : 'border-slate-200 bg-white')}>
        <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
          <div>
            <p className={clsx('text-xs font-black uppercase tracking-widest mb-0.5', isDark ? 'text-cyan-400' : 'text-cyan-600')}>
              {dayLabel} Timeline
            </p>
            <h1 className={clsx('text-2xl font-black', isDark ? 'text-white' : 'text-slate-900')}>
              {now.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}
            </h1>
            <p className={clsx('mt-1 text-sm font-semibold', isDark ? 'text-white/50' : 'text-slate-500')}>
              Complete today&apos;s routine before 10:00 PM.
            </p>
          </div>
          <div className="grid grid-cols-3 gap-2 md:min-w-[320px]">
            <div className={clsx('rounded-xl border px-3 py-2 text-center', isDark ? 'border-emerald-400/20 bg-emerald-400/10' : 'border-emerald-100 bg-emerald-50')}>
              <p className={clsx('text-xl font-black', isDark ? 'text-emerald-300' : 'text-emerald-600')}>{completedCount}</p>
              <p className={clsx('text-[10px] font-black uppercase tracking-wider', isDark ? 'text-white/45' : 'text-slate-500')}>Done</p>
            </div>
            <div className={clsx('rounded-xl border px-3 py-2 text-center', isDark ? 'border-amber-400/20 bg-amber-400/10' : 'border-amber-100 bg-amber-50')}>
              <p className={clsx('text-xl font-black', isDark ? 'text-amber-300' : 'text-amber-600')}>{pendingCount}</p>
              <p className={clsx('text-[10px] font-black uppercase tracking-wider', isDark ? 'text-white/45' : 'text-slate-500')}>Pending</p>
            </div>
            <div className={clsx('rounded-xl border px-3 py-2 text-center', isPastLockout ? (isDark ? 'border-rose-400/20 bg-rose-400/10' : 'border-rose-100 bg-rose-50') : (isDark ? 'border-cyan-400/20 bg-cyan-400/10' : 'border-cyan-100 bg-cyan-50'))}>
              <p className={clsx('text-xl font-black', isPastLockout ? (isDark ? 'text-rose-300' : 'text-rose-600') : (isDark ? 'text-cyan-300' : 'text-cyan-600'))}>{isPastLockout ? 'Locked' : '10 PM'}</p>
              <p className={clsx('text-[10px] font-black uppercase tracking-wider', isDark ? 'text-white/45' : 'text-slate-500')}>Deadline</p>
            </div>
          </div>
        </div>
        <div className="mt-4 flex justify-end">
          <button
            onClick={() => setShowAddModal(true)}
            className="flex items-center gap-1.5 rounded-xl bg-cyan-500 px-3.5 py-2 text-sm font-bold text-white hover:bg-cyan-400 transition-colors shadow-lg shadow-cyan-500/30"
          >
            <Plus size={15} /> Add
          </button>
        </div>
      </div>

      {/* 10 PM lockout warning */}
      {isPastLockout && (
        <div className={clsx('mb-5 flex items-center gap-3 rounded-2xl border px-4 py-3 text-sm font-semibold',
          isDark ? 'bg-amber-500/10 border-amber-500/30 text-amber-300' : 'bg-amber-50 border-amber-200 text-amber-700'
        )}>
          <Lock size={16} />
          <span>Routines are locked after 10 PM. Incomplete routines will break your streak.</span>
        </div>
      )}

      {/* No routines */}
      {timeline.length === 0 ? (
        <div className={clsx('rounded-2xl border border-dashed p-10 text-center', isDark ? 'border-white/10' : 'border-slate-200')}>
          <Clock size={32} className={clsx('mx-auto mb-3', isDark ? 'text-white/20' : 'text-slate-300')} />
          <p className={clsx('font-bold', isDark ? 'text-white/40' : 'text-slate-400')}>
            No {dayLabel.toLowerCase()} routines today.
          </p>
          <p className={clsx('text-sm mt-1', isDark ? 'text-white/30' : 'text-slate-400')}>
            Ask your parents to set up routines, or add your own!
          </p>
        </div>
      ) : (
        /* Timeline */
        <div className="relative">
          {/* Vertical line */}
          <div className={clsx('absolute left-[28px] top-0 bottom-0 w-0.5', isDark ? 'bg-white/10' : 'bg-slate-200')} />

          <div className="space-y-3">
            {timeline.map(routine => {
              const log = todayLogs[routine.id];
              const isCompleted = log?.status === 'completed';
              const isSick = log?.status === 'sick';
              const isMissed = log?.status === 'missed';
              const isLocked = isPastLockout && !isCompleted;

              return (
                <div key={routine.id} className="flex gap-4 relative">
                  {/* Timeline dot */}
                  <div className={clsx(
                    'relative z-10 flex-shrink-0 w-14 flex flex-col items-center gap-1 pt-3'
                  )}>
                    <div className={clsx(
                      'w-8 h-8 rounded-full flex items-center justify-center text-base border-2 flex-shrink-0',
                      isCompleted
                        ? 'bg-emerald-500 border-emerald-400 text-white'
                        : isSick
                        ? 'bg-amber-400 border-amber-300 text-white'
                        : isMissed
                        ? 'bg-rose-400 border-rose-300 text-white'
                        : isLocked
                        ? (isDark ? 'bg-white/5 border-white/10' : 'bg-slate-100 border-slate-200')
                        : (isDark ? 'bg-white/10 border-white/20' : 'bg-white border-slate-300 shadow-sm')
                    )}>
                      {isCompleted ? <CheckCircle2 size={16} /> : isMissed ? <X size={15} /> : routine.icon || '📝'}
                    </div>
                    <p className={clsx('text-[10px] font-bold text-center leading-tight', isDark ? 'text-white/40' : 'text-slate-400')}>
                      {fmtTime(routine.start_time || routine.schedule_time || '')}
                    </p>
                  </div>

                  {/* Card */}
                  <div className={clsx(
                    'flex-1 rounded-2xl border p-4 transition-all mb-1',
                    isCompleted
                      ? (isDark ? 'bg-emerald-500/10 border-emerald-500/25' : 'bg-emerald-50 border-emerald-200')
                      : isMissed
                      ? (isDark ? 'bg-rose-500/10 border-rose-500/25 opacity-70' : 'bg-rose-50 border-rose-200 opacity-80')
                      : isLocked
                      ? (isDark ? 'bg-white/3 border-white/5 opacity-50' : 'bg-slate-50 border-slate-100 opacity-60')
                      : (isDark ? 'bg-white/5 border-white/10 hover:bg-white/8' : 'bg-white border-slate-200 hover:shadow-md')
                  )}>
                    <div className="flex items-center justify-between mb-2">
                      <div>
                        <h3 className={clsx(
                          'font-bold text-base leading-tight',
                          isDark ? 'text-white' : 'text-slate-900',
                          isCompleted && 'line-through opacity-60'
                        )}>
                          {routine.title}
                        </h3>
                        <p className={clsx('text-xs font-semibold mt-0.5', isDark ? 'text-white/40' : 'text-slate-400')}>
                          {fmtTime(routine.start_time || routine.schedule_time || '')} – {fmtTime(routine.end_time || '')}
                        </p>
                      </div>
                      <div className="flex flex-col items-end gap-1">
                        <span className={clsx('text-xs font-bold flex items-center gap-0.5', isDark ? 'text-emerald-400' : 'text-emerald-600')}>
                          <Star size={12} className="fill-current" /> {routine.points} stars
                        </span>
                        {isCompleted && log?.stars_awarded === 0 && (
                          <span className={clsx('text-[10px] font-bold', isDark ? 'text-amber-300' : 'text-amber-600')}>No stars</span>
                        )}
                        {isMissed && (
                          <span className={clsx('text-[10px] font-bold', isDark ? 'text-rose-300' : 'text-rose-600')}>-{Math.abs(Number(log?.stars_delta || routine.points || 0))} stars</span>
                        )}
                        {(routine.streak > 0) && (
                          <span className={clsx('text-xs font-bold flex items-center gap-0.5', isDark ? 'text-orange-400' : 'text-orange-600')}>
                            <Flame size={12} className="fill-current" /> {routine.streak}
                          </span>
                        )}
                      </div>
                    </div>

                    {routine.requires_approval && !isCompleted && (
                      <p className={clsx('text-[10px] font-bold mb-2', isDark ? 'text-amber-400/80' : 'text-amber-600')}>
                        ⚠️ Needs parent approval for stars
                      </p>
                    )}

                    <button
                      disabled={isCompleted || isSick || isMissed || isLocked || loggingId === routine.id}
                      onClick={() => handleComplete(routine.id)}
                      className={clsx(
                        'w-full py-2.5 rounded-xl text-sm font-bold transition-all flex items-center justify-center gap-2',
                        isCompleted
                          ? 'bg-emerald-500 text-white cursor-default'
                        : isSick
                        ? 'bg-amber-400 text-white cursor-default'
                        : isMissed
                        ? 'bg-rose-400 text-white cursor-default'
                        : isLocked
                        ? (isDark ? 'bg-white/5 text-white/30 cursor-not-allowed' : 'bg-slate-100 text-slate-300 cursor-not-allowed')
                          : 'bg-cyan-500 text-white hover:bg-cyan-400 hover:scale-[1.02] shadow-md shadow-cyan-500/20'
                      )}
                    >
                      {loggingId === routine.id ? (
                        <span className="animate-pulse">Logging...</span>
                      ) : isCompleted ? (
                        <><CheckCircle2 size={16} /> Done!</>
                      ) : isSick ? (
                        <>🤒 Sick Mode</>
                      ) : isMissed ? (
                        <>Missed</>
                      ) : isLocked ? (
                        <><Lock size={14} /> Locked (10 PM)</>
                      ) : (
                        'Mark Complete'
                      )}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {starCelebration && (
        <div className="fixed inset-0 z-[70] grid place-items-center bg-black/35 px-4 backdrop-blur-sm">
          <div className={clsx('relative w-full max-w-sm overflow-hidden rounded-3xl border p-6 text-center shadow-2xl', isDark ? 'border-amber-300/30 bg-slate-950 text-white' : 'border-amber-200 bg-white text-slate-900')}>
            <div className="absolute -left-8 top-4 h-20 w-20 rounded-full bg-amber-300/25 blur-2xl" />
            <div className="absolute -right-8 bottom-4 h-24 w-24 rounded-full bg-cyan-300/25 blur-2xl" />
            <div className="relative mx-auto grid h-20 w-20 animate-bounce place-items-center rounded-full bg-amber-300 text-4xl shadow-[0_0_35px_rgba(251,191,36,0.75)]">
              <Star className="h-10 w-10 fill-white text-white" />
            </div>
            <p className="relative mt-4 text-3xl font-black text-amber-400">+{starCelebration.stars}</p>
            <p className="relative mt-1 text-sm font-bold opacity-75">{starCelebration.title}</p>
          </div>
        </div>
      )}

      {completionRoutine && (
        <div className="fixed inset-0 z-[65] flex items-end justify-center bg-black/60 p-4 backdrop-blur-sm sm:items-center">
          <form
            onSubmit={submitCompletionTime}
            className={clsx('w-full max-w-md rounded-3xl border p-5 shadow-2xl', isDark ? 'border-white/10 bg-[#1a1f3c]' : 'border-slate-200 bg-white')}
          >
            <div className="mb-4 flex items-start justify-between gap-3">
              <div>
                <p className={clsx('text-xs font-black uppercase tracking-widest', isDark ? 'text-cyan-300' : 'text-cyan-600')}>Completion Time</p>
                <h3 className={clsx('mt-1 text-lg font-black', isDark ? 'text-white' : 'text-slate-900')}>{completionRoutine.title}</h3>
                <p className={clsx('mt-1 text-sm font-semibold', isDark ? 'text-white/55' : 'text-slate-500')}>
                  Routine window: {fmtTime(completionRoutine.start_time || completionRoutine.schedule_time || '')} - {fmtTime(completionRoutine.end_time || '')}
                </p>
              </div>
              <button type="button" onClick={() => setCompletionRoutine(null)} className={clsx('rounded-full p-2', isDark ? 'text-white/45 hover:bg-white/10 hover:text-white' : 'text-slate-400 hover:bg-slate-100 hover:text-slate-700')}>
                <X size={18} />
              </button>
            </div>
            <label className={clsx('mb-1 block text-xs font-bold uppercase tracking-wider', isDark ? 'text-white/50' : 'text-slate-500')}>When did you actually finish?</label>
            <input
              required
              type="time"
              value={actualCompletionTime}
              onChange={(event) => setActualCompletionTime(event.target.value)}
              className={clsx('w-full rounded-2xl border px-4 py-3 text-lg font-black outline-none focus:ring-2 focus:ring-cyan-500/50', isDark ? 'border-white/10 bg-black/20 text-white' : 'border-slate-300 bg-white text-slate-900')}
            />
